fn handle_map_window(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    origin: Option<OriginContext>,
    client_id: ClientId,
    sequence: SequenceNumber,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    let Some(window) = x11::map_window_id(body) else {
        return Ok(RequestOutcome::Handled);
    };
    let Some((parent, override_redirect)) = state
        .resources
        .window(window)
        .map(|w| (w.parent, w.override_redirect))
    else {
        return Ok(RequestOutcome::Handled);
    };

    // SubstructureRedirect on the parent: forward MapRequest to the
    // first subscriber that isn't the requester (the WM), and skip
    // mapping locally.
    let redirect_targets: Vec<ClientId> = if !override_redirect {
        let requester_has = state
            .clients
            .get(&client_id.0)
            .and_then(|c| c.event_masks.get(&parent).copied())
            .is_some_and(|m| m & 0x0010_0000 != 0);
        if requester_has {
            Vec::new()
        } else {
            subscribers_by_id(state, parent, 0x0010_0000)
        }
    } else {
        Vec::new()
    };

    if !redirect_targets.is_empty() {
        debug!(
            "client {} MapWindow 0x{:x} -> MapRequest to WM",
            client_id.0, window.0
        );
        let _dropped = fanout_event_to_clients(state, &redirect_targets, |buf, seq, order| {
            x11::encode_map_request_event(buf, seq, order, parent, window);
        });
        return Ok(RequestOutcome::Handled);
    }

    // Per X11 protocol: "If the window is already mapped, this request
    // has no effect." Without this guard a client that pounds MapWindow
    // on an already-viewable popup (brisk-menu's GTK3
    // `gtk_window_present` loop hits this at ~50 Hz) causes a fresh
    // MapNotify → Expose → full-extent damage cascade every call. Marco
    // reacts to each MapNotify with a `COMPOSITE::NameWindowPixmap` and
    // full recomposite, which is visible as menu flicker on KMS.
    let was_unmapped = state.resources.map_window(window);
    if !was_unmapped {
        debug!(
            "client {} #{} MapWindow 0x{:x} (already mapped — no-op)",
            client_id.0, sequence.0, window.0
        );
        return Ok(RequestOutcome::Handled);
    }
    let host_xid = state.resources.window(window).and_then(|w| w.host_xid);
    let map_info = state
        .resources
        .window(window)
        .map(|w| (w.parent, w.override_redirect));
    if let Some(xid) = host_xid {
        let _ = backend.map_subwindow(origin, xid.as_raw());
        // Stage 4b.7: if the window's parent has a
        // `RedirectSubwindows(mode)` record, the newly-mapped child
        // needs its own backing (per Composite spec: "redirected
        // hierarchy pixels are available whenever it is viewable",
        // and Xorg activates on realize at `compwindow.c:267`).
        // AFTER `map_subwindow` per the plan's codex-round-6
        // ordering fix — `map_subwindow` blindly flips
        // `scene_participating = true`, so the Manual
        // participation flip inside `activate_redirect_backing_for`
        // (sets it back to false) must land last.
        maybe_activate_child_under_redirected_parent(state, backend, origin, window);
        reapply_redirect_mode_after_map(state, backend, origin, window);
    }

    let wants_focus = {
        let mask = state
            .clients
            .get(&client_id.0)
            .and_then(|c| c.event_masks.get(&window).copied())
            .unwrap_or(0);
        let viewable = state
            .resources
            .window(window)
            .is_some_and(|w| w.map_state == MapState::Viewable);
        viewable && (mask & 0x3) != 0
    };
    if wants_focus {
        debug!("focus key window 0x{:x}", window.0);
        set_focused_window_to_state(state, client_id, window);
    }

    if let Some((parent, override_redir)) = map_info {
        let _dropped = emit_window_event_to_state(state, window, 0x0002_0000, |buf, seq, order| {
            x11::encode_map_notify_event(buf, seq, order, window, window, override_redir);
        });
        let _dropped = emit_window_event_to_state(state, parent, 0x0008_0000, |buf, seq, order| {
            x11::encode_map_notify_event(buf, seq, order, parent, window, override_redir);
        });
        // Emit VisibilityNotify(Unobscured) then Expose on the window
        // itself when it becomes viewable. Subscribed clients want the
        // newly-viewable window to redraw.
        let extents = state
            .resources
            .window(window)
            .filter(|w| w.map_state == crate::resources::MapState::Viewable)
            .map(|w| (w.width, w.height));
        if let Some((w, h)) = extents {
            // VisibilityNotify(Unobscured) for clients selecting
            // VisibilityChangeMask (0x10000). Under yserver's compositor
            // model every viewable top-level is effectively unobscured.
            // Without this, GTK3 leaves the window in a non-paintable
            // visibility state and suppresses all frame-clock paints
            // after the first expose-driven frame — the
            // cinnamon-settings "title changes but content never
            // repaints" freeze. Xorg sends Unobscured on map; we mirror
            // that. (We never send Obscured: a composited top-level is
            // always paintable, and unmap is signalled by UnmapNotify
            // per spec, not VisibilityNotify.)
            let _dropped =
                emit_window_event_to_state(state, window, 0x0001_0000, |buf, seq, order| {
                    x11::encode_visibility_notify_event(buf, seq, order, window, 0);
                });
            // Descendants that were MapWindow'd while this window was
            // still unmapped were Unviewable; mapping this window
            // transitions them to Viewable. Xorg fires
            // VisibilityNotify(Unobscured) on every such descendant
            // (mate-xorg.xtrace seq 0x0147 shows VisibilityNotify on
            // both the FF main window and its child 0x02400010).
            // yserver previously only notified the directly-mapped
            // window, so GTK3's frame clock for the child never woke
            // and the profile chooser stayed blank — the "empty shadow"
            // FF bug on bee. Order with the Expose subtree walk below
            // doesn't matter; both are subtree-wide and idempotent.
            let _dropped = emit_visibility_unobscured_subtree_to_state(state, window);
            let _dropped =
                emit_window_event_to_state(state, window, 0x0000_8000, |buf, seq, order| {
                    x11::encode_expose_event(buf, seq, order, window, 0, 0, w, h, 0);
                });
            let _dropped = emit_expose_subtree_to_state(state, window);
        }
    }
    // Audit #11: Xorg's `miPaintWindow` fires damage on the window's
    // extent when the window becomes viewable (the server-background
    // fill is itself a paint, and DAMAGE hooks every paint).
    // Compositors that subscribe via `XDamageCreate(window)` rely on
    // that first DamageNotify to read the freshly-mapped window's
    // pixels into their own offscreen.
    //
    // Order matters: this MUST come AFTER the MapNotify emissions
    // above. Marco subscribes to SubstructureNotify on root, registers
    // the window in its compositor tree on receiving MapNotify, and
    // only then accepts DAMAGE-Notify on it as a NameWindowPixmap
    // trigger. Pre-fix (damage emitted before MapNotify) marco saw the
    // damage on a window it didn't yet track and silently dropped it,
    // causing mate-panel-top to render blank until a later resize
    // damage finally landed. See mate.xtrace lines 4938→4940 vs
    // mate-xorg.xtrace lines 5164→5173.
    if host_xid.is_some() {
        let _dropped = accumulate_damage_full_to_state(state, window);
        accumulate_damage_viewable_descendants_to_state(state, window);
    }
    debug!(
        "client {} #{} MapWindow 0x{:x}",
        client_id.0, sequence.0, window.0
    );
    Ok(RequestOutcome::Handled)
}

fn accumulate_damage_viewable_descendants_to_state(state: &mut ServerState, root: ResourceId) {
    let children: Vec<ResourceId> = state.resources.children(root).to_vec();
    for child in children {
        let viewable = state
            .resources
            .window(child)
            .is_some_and(|w| w.map_state == MapState::Viewable);
        if !viewable {
            continue;
        }
        let _dropped = accumulate_damage_full_to_state(state, child);
        accumulate_damage_viewable_descendants_to_state(state, child);
    }
}

fn handle_map_subwindows(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    origin: Option<OriginContext>,
    client_id: ClientId,
    sequence: SequenceNumber,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    let Some(parent) = x11::map_window_id(body) else {
        return Ok(RequestOutcome::Handled);
    };
    let children: Vec<ResourceId> = state.resources.children(parent).to_vec();
    for child in children {
        let was_unmapped = state.resources.map_window(child);
        let host_xid = state.resources.window(child).and_then(|w| w.host_xid);
        let extents = state.resources.window(child).map(|w| (w.width, w.height));
        let override_redirect = state
            .resources
            .window(child)
            .is_some_and(|w| w.override_redirect);
        if let Some(xid) = host_xid {
            let _ = backend.map_subwindow(origin, xid.as_raw());
            // Stage 4b.7: same post-hook as `handle_map_window`.
            // Activation MUST run AFTER `map_subwindow` per the
            // plan's round-6 ordering fix.
            maybe_activate_child_under_redirected_parent(state, backend, origin, child);
            reapply_redirect_mode_after_map(state, backend, origin, child);
            // Audit #11: see `handle_map_window` for the rationale.
            // Mirror the damage bump so MapSubwindows-driven mass
            // maps (mate-panel applet realize cascade, GTK
            // children-on-show) also notify subscribed compositors.
            let _dropped = accumulate_damage_full_to_state(state, child);
        }
        if window_wants_keyboard_focus(state, client_id, child) {
            debug!(
                "focus decision: client {} MapSubwindows focus 0x{:x}",
                client_id.0, child.0
            );
            set_focused_window_to_state(state, client_id, child);
        }
        if was_unmapped {
            let _dropped =
                emit_window_event_to_state(state, child, 0x0002_0000, |buf, seq, order| {
                    x11::encode_map_notify_event(buf, seq, order, child, child, override_redirect);
                });
            let _dropped =
                emit_window_event_to_state(state, parent, 0x0008_0000, |buf, seq, order| {
                    x11::encode_map_notify_event(buf, seq, order, parent, child, override_redirect);
                });
        }
        // Only emit Expose if the child is now Viewable (parent must
        // also be mapped). When the parent is unmapped, mapping the
        // child changes its `map_state` to `Mapped` but not `Viewable`,
        // and the spec only fires Expose for newly-viewable areas.
        let viewable = state
            .resources
            .window(child)
            .is_some_and(|w| w.map_state == MapState::Viewable);
        if was_unmapped
            && viewable
            && let Some((width, height)) = extents
        {
            let _dropped =
                emit_window_event_to_state(state, child, 0x0000_8000, |buf, seq, order| {
                    x11::encode_expose_event(buf, seq, order, child, 0, 0, width, height, 0);
                });
        }
    }
    debug!("client {} #{} MapSubwindows", client_id.0, sequence.0);
    Ok(RequestOutcome::Handled)
}

fn handle_unmap_window(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    origin: Option<OriginContext>,
    client_id: ClientId,
    sequence: SequenceNumber,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    if let Some(window) = x11::map_window_id(body) {
        let host_xid = state.resources.window(window).and_then(|w| w.host_xid);
        let was_mapped = state.resources.unmap_window(window);
        let parent = if was_mapped {
            state
                .resources
                .window(window)
                .map_or(ROOT_WINDOW, |w| w.parent)
        } else {
            ROOT_WINDOW
        };
        if let Some(xid) = host_xid {
            let _ = backend.unmap_subwindow(origin, xid.as_raw());
        }
        if was_mapped {
            let _dropped =
                emit_window_event_to_state(state, window, 0x0002_0000, |buf, seq, order| {
                    x11::encode_unmap_notify_event(buf, seq, order, window, window, false);
                });
            let _dropped =
                emit_window_event_to_state(state, parent, 0x0008_0000, |buf, seq, order| {
                    x11::encode_unmap_notify_event(buf, seq, order, parent, window, false);
                });
        }
    }
    debug!("client {} #{} UnmapWindow", client_id.0, sequence.0);
    Ok(RequestOutcome::Handled)
}

fn handle_unmap_subwindows(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    origin: Option<OriginContext>,
    client_id: ClientId,
    sequence: SequenceNumber,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    let Some(parent) = x11::map_window_id(body) else {
        return Ok(RequestOutcome::Handled);
    };
    struct PendingUnmap {
        child: ResourceId,
        host_xid: Option<crate::backend::WindowHandle>,
    }
    let Some(children) = state.resources.mapped_children_bottom_to_top(parent) else {
        return emit_x11_error(
            state,
            client_id,
            sequence,
            x11::error::BAD_WINDOW,
            parent.0,
            11,
        );
    };
    // Snapshot mapping order + collect host xids; unmap each in the
    // resource table.
    let mut pending: Vec<PendingUnmap> = Vec::new();
    for child in children {
        let host_xid = state.resources.window(child).and_then(|w| w.host_xid);
        if state.resources.unmap_window(child) {
            pending.push(PendingUnmap { child, host_xid });
        }
    }
    for item in pending {
        if let Some(xid) = item.host_xid {
            let _ = backend.unmap_subwindow(origin, xid.as_raw());
        }
        let child = item.child;
        let _dropped = emit_window_event_to_state(state, child, 0x0002_0000, |buf, seq, order| {
            x11::encode_unmap_notify_event(buf, seq, order, child, child, false);
        });
        let _dropped = emit_window_event_to_state(state, parent, 0x0008_0000, |buf, seq, order| {
            x11::encode_unmap_notify_event(buf, seq, order, parent, child, false);
        });
    }
    debug!("client {} #{} UnmapSubwindows", client_id.0, sequence.0);
    Ok(RequestOutcome::Handled)
}

fn handle_ge_request(
    state: &mut ServerState,
    client_id: ClientId,
    sequence: SequenceNumber,
    header: RequestHeader,
) -> io::Result<RequestOutcome> {
    if header.data == 0 {
        debug!("client {} #{} GEQueryVersion", client_id.0, sequence.0);
        let Some(client) = state.clients.get_mut(&client_id.0) else {
            return Ok(RequestOutcome::Handled);
        };
        let byte_order = client.byte_order;
        let mut buf: Vec<u8> = Vec::with_capacity(32);
        x11::write_ge_query_version_reply(&mut buf, byte_order, sequence)?;
        return Ok(write_to_client(client, client_id, &buf));
    }
    Ok(RequestOutcome::Handled)
}

fn handle_big_requests_request(
    state: &mut ServerState,
    client_id: ClientId,
    sequence: SequenceNumber,
    header: RequestHeader,
) -> io::Result<RequestOutcome> {
    if header.data != 0 {
        // Malformed minor — the reader thread parked waiting for an
        // Apply / Ignore signal after sending the Enable through the
        // channel; unblock it with `IgnoreBigRequests` so it doesn't
        // deadlock.
        if let Some(client) = state.clients.get(&client_id.0)
            && let Some(tx) = client.reader_control.as_ref()
        {
            let _ = tx.send(crate::server::ReaderControl::IgnoreBigRequests);
        }
        return Ok(RequestOutcome::Handled);
    }
    debug!("client {} #{} BigRequestsEnable", client_id.0, sequence.0);
    let Some(client) = state.clients.get_mut(&client_id.0) else {
        return Ok(RequestOutcome::Handled);
    };
    let byte_order = client.byte_order;
    client.big_requests_enabled = true;
    let mut buf: Vec<u8> = Vec::with_capacity(32);
    x11::write_big_requests_enable_reply(&mut buf, byte_order, sequence, 256 * 1024)?;
    let outcome = write_to_client(client, client_id, &buf);
    // Unblock the reader so subsequent requests use big-framing.
    if let Some(tx) = client.reader_control.as_ref() {
        let _ = tx.send(crate::server::ReaderControl::ApplyBigRequests);
    }
    Ok(outcome)
}

fn handle_get_window_attributes(
    state: &mut ServerState,
    client_id: ClientId,
    sequence: SequenceNumber,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    debug!("client {} #{} GetWindowAttributes", client_id.0, sequence.0);
    let id = x11::drawable_request_id(body).unwrap_or(ROOT_WINDOW);
    // Spec: BadWindow on unknown window ID. Don't silently fall back to
    // ROOT_WINDOW — xts probes stale/destroyed XIDs and expects the
    // protocol error.
    if state.resources.window(id).is_none() {
        return emit_x11_error(state, client_id, sequence, x11::error::BAD_WINDOW, id.0, 3);
    }
    let target = id;
    let your_event_mask = state
        .clients
        .get(&client_id.0)
        .and_then(|c| c.event_masks.get(&target).copied())
        .unwrap_or(0);
    let all_event_masks: u32 = state
        .clients
        .values()
        .filter_map(|c| c.event_masks.get(&target).copied())
        .fold(0u32, |a, b| a | b);
    let attrs = window_attributes(
        state.resources.window(target),
        all_event_masks,
        your_event_mask,
    );
    let Some(client) = state.clients.get_mut(&client_id.0) else {
        return Ok(RequestOutcome::Handled);
    };
    let byte_order = client.byte_order;
    let mut buf: Vec<u8> = Vec::with_capacity(48);
    x11::write_get_window_attributes_reply(&mut buf, byte_order, sequence, attrs)?;
    Ok(write_to_client(client, client_id, &buf))
}

fn window_attributes(
    window: Option<&Window>,
    all_event_masks: u32,
    your_event_mask: u32,
) -> x11::WindowAttributes {
    let window = window.expect("root window exists");
    x11::WindowAttributes {
        visual: window.visual,
        class: window.class.protocol_value(),
        bit_gravity: window.bit_gravity,
        win_gravity: window.win_gravity,
        backing_store: window.backing_store,
        backing_planes: window.backing_planes,
        backing_pixel: window.backing_pixel,
        save_under: window.save_under,
        map_is_installed: true,
        map_state: window.map_state.protocol_value(),
        override_redirect: window.override_redirect,
        colormap: window.colormap,
        all_event_masks,
        your_event_mask,
        do_not_propagate_mask: window.do_not_propagate_mask,
    }
}

fn handle_circulate_window(
    state: &mut ServerState,
    client_id: ClientId,
    sequence: SequenceNumber,
    header: RequestHeader,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    if body.len() < 4 {
        debug!(
            "client {} #{} CirculateWindow (short body)",
            client_id.0, sequence.0
        );
        return Ok(RequestOutcome::Handled);
    }
    let container = ResourceId(u32::from_le_bytes([body[0], body[1], body[2], body[3]]));
    let direction = header.data;
    let chosen_child = {
        let kids = state.resources.children(container);
        match (direction, kids.first(), kids.last()) {
            (0, _, Some(&back)) => Some(back),
            (1, Some(&front), _) => Some(front),
            _ => None,
        }
    };
    let Some(child) = chosen_child else {
        return Ok(RequestOutcome::Handled);
    };
    // SubstructureRedirect on container takes priority — redirect the
    // request to the first subscriber instead of performing the
    // circulate.
    let redirect_target = subscribers_by_id(state, container, 0x0010_0000)
        .into_iter()
        .next();
    if let Some(target) = redirect_target {
        let _dropped = fanout_event_to_clients(state, &[target], |buf, seq, order| {
            let _ =
                x11::write_circulate_request_event(buf, order, seq, container, child, direction);
        });
    } else {
        let _ = state.resources.circulate_window(container, direction);
        let on_child = subscribers_by_id(state, child, 0x0002_0000);
        let on_container = subscribers_by_id(state, container, 0x0008_0000);
        let mut targets = on_child;
        for cid in on_container {
            if !targets.contains(&cid) {
                targets.push(cid);
            }
        }
        let _dropped = fanout_event_to_clients(state, &targets, |buf, seq, order| {
            let _ = x11::write_circulate_notify_event(buf, order, seq, child, child, direction);
        });
    }
    debug!("client {} #{} CirculateWindow", client_id.0, sequence.0);
    Ok(RequestOutcome::Handled)
}

fn handle_create_cursor(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    origin: Option<OriginContext>,
    client_id: ClientId,
    sequence: SequenceNumber,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    if body.len() >= 28 {
        let cursor_id = ResourceId(u32::from_le_bytes([body[0], body[1], body[2], body[3]]));
        if state.resources.xid_in_use(cursor_id)
            || xid_out_of_client_range(state, client_id, cursor_id.0)
        {
            return emit_x11_error(
                state,
                client_id,
                sequence,
                x11::error::BAD_ID_CHOICE,
                cursor_id.0,
                93,
            );
        }
        let source_id = ResourceId(u32::from_le_bytes([body[4], body[5], body[6], body[7]]));
        let mask_id = ResourceId(u32::from_le_bytes([body[8], body[9], body[10], body[11]]));
        let fore = (
            u16::from_le_bytes([body[12], body[13]]),
            u16::from_le_bytes([body[14], body[15]]),
            u16::from_le_bytes([body[16], body[17]]),
        );
        let back = (
            u16::from_le_bytes([body[18], body[19]]),
            u16::from_le_bytes([body[20], body[21]]),
            u16::from_le_bytes([body[22], body[23]]),
        );
        let hot_x = u16::from_le_bytes([body[24], body[25]]);
        let hot_y = u16::from_le_bytes([body[26], body[27]]);

        let src_host = state.resources.pixmap(source_id).and_then(|p| p.host_xid);
        let mask_host = if mask_id.0 == 0 {
            None
        } else {
            state.resources.pixmap(mask_id).and_then(|p| p.host_xid)
        };
        state.resources.create_cursor(client_id, cursor_id);
        if let Some(src_host) = src_host {
            match backend.create_cursor(origin, src_host, mask_host, fore, back, hot_x, hot_y) {
                Ok(handle) => {
                    state.resources.set_cursor_host_xid(cursor_id, handle);
                }
                Err(err) => {
                    log::warn!("client {} CreateCursor failed: {err}", client_id.0);
                }
            }
        }
    }
    debug!("client {} #{} CreateCursor", client_id.0, sequence.0);
    Ok(RequestOutcome::Handled)
}

fn handle_create_glyph_cursor(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    origin: Option<OriginContext>,
    client_id: ClientId,
    sequence: SequenceNumber,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    if body.len() >= 28
        && let Some(cursor) = x11::create_glyph_cursor_id(body)
    {
        let new_id = cursor.0;
        let validation_failed = {
            let handle = state.clients.get(&client_id.0).expect("client registered");
            let owned = crate::server::IdAllocator::validate_owned(
                new_id,
                handle.resource_id_base,
                handle.resource_id_mask,
            );
            let in_use = state.resources.any_resource_exists(cursor);
            !owned || in_use
        };
        if validation_failed {
            return emit_x11_error(
                state,
                client_id,
                sequence,
                x11::error::BAD_ID_CHOICE,
                new_id,
                94,
            );
        }

        let source_id = ResourceId(u32::from_le_bytes([body[4], body[5], body[6], body[7]]));
        let mask_id = ResourceId(u32::from_le_bytes([body[8], body[9], body[10], body[11]]));
        let source_char = u16::from_le_bytes([body[12], body[13]]);
        let mask_char = u16::from_le_bytes([body[14], body[15]]);
        let fore = (
            u16::from_le_bytes([body[16], body[17]]),
            u16::from_le_bytes([body[18], body[19]]),
            u16::from_le_bytes([body[20], body[21]]),
        );
        let back = (
            u16::from_le_bytes([body[22], body[23]]),
            u16::from_le_bytes([body[24], body[25]]),
            u16::from_le_bytes([body[26], body[27]]),
        );

        let src_host = state.resources.font(source_id).map(|f| f.host_xid);
        let mask_host = if mask_id.0 == 0 {
            None
        } else {
            state.resources.font(mask_id).map(|f| f.host_xid)
        };

        state.resources.create_glyph_cursor(client_id, cursor);
        if let Some(src_host) = src_host {
            match backend.create_glyph_cursor(
                origin,
                src_host,
                mask_host,
                source_char,
                mask_char,
                fore,
                back,
            ) {
                Ok(handle) => {
                    state.resources.set_cursor_host_xid(cursor, handle);
                }
                Err(err) => {
                    log::warn!("client {} CreateGlyphCursor failed: {err}", client_id.0);
                }
            }
        } else {
            log::warn!(
                "client {} CreateGlyphCursor: source font 0x{:x} unknown",
                client_id.0,
                source_id.0
            );
        }
    }
    debug!("client {} #{} CreateGlyphCursor", client_id.0, sequence.0);
    Ok(RequestOutcome::Handled)
}

fn handle_query_extension(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    client_id: ClientId,
    sequence: SequenceNumber,
    body: &[u8],
) -> io::Result<RequestOutcome> {
    let name = x11::query_extension_name(body);
    let (present, major_opcode, first_event, first_error) = extension_query_reply(&name, backend)
        .map(|(major_opcode, first_event, first_error)| {
            (true, major_opcode, first_event, first_error)
        })
        .unwrap_or((false, 0, 0, 0));
    debug!(
        "client {} #{} QueryExtension {:?} -> {}",
        client_id.0,
        sequence.0,
        name,
        if present { "present" } else { "absent" }
    );
    let Some(client) = state.clients.get_mut(&client_id.0) else {
        return Ok(RequestOutcome::Handled);
    };
    let byte_order = client.byte_order;
    let mut buf: Vec<u8> = Vec::with_capacity(32);
    x11::write_query_extension_reply(
        &mut buf,
        byte_order,
        sequence,
        present,
        major_opcode,
        first_event,
        first_error,
    )?;
    Ok(write_to_client(client, client_id, &buf))
}

fn handle_list_extensions(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    client_id: ClientId,
    sequence: SequenceNumber,
) -> io::Result<RequestOutcome> {
    debug!("client {} #{} ListExtensions", client_id.0, sequence.0);
    let names = advertised_extension_names(backend);
    let Some(client) = state.clients.get_mut(&client_id.0) else {
        return Ok(RequestOutcome::Handled);
    };
    let byte_order = client.byte_order;
    let mut buf: Vec<u8> = Vec::with_capacity(32 + names.len() * 16);
    x11::write_list_extensions_reply(&mut buf, byte_order, sequence, &names)?;
    Ok(write_to_client(client, client_id, &buf))
}

fn handle_allow_events(
    state: &mut ServerState,
    backend: &mut dyn Backend,
    client_id: ClientId,
    sequence: SequenceNumber,
    header: RequestHeader,
) -> io::Result<RequestOutcome> {
    // Core AllowEvents modes (X11 spec):
    //   0 AsyncPointer  1 SyncPointer   2 ReplayPointer
    //   3 AsyncKeyboard 4 SyncKeyboard  5 ReplayKeyboard
    //   6 AsyncBoth     7 SyncBoth
    let mode = header.data;
    debug!(
        "client {} #{} AllowEvents mode={} frozen_pointer={} frozen_keyboard={}",
        client_id.0,
        sequence.0,
        mode,
        state.frozen_pointer_event.is_some(),
        state.frozen_keyboard_event.is_some(),
    );

    // Pointer side: AsyncPointer / SyncPointer / ReplayPointer, plus
    // the *Both modes which thaw the pointer too.
    let pointer_release = matches!(mode, 0 | 1 | 2 | 6 | 7);
    let pointer_replay = mode == 2;
    // Keyboard side: AsyncKeyboard / SyncKeyboard / ReplayKeyboard,
    // plus the *Both modes.
    let keyboard_release = matches!(mode, 3..=7);
    let keyboard_replay = mode == 5;

    let frozen_pointer = if pointer_release {
        state.frozen_pointer_event.take()
    } else {
        None
    };
    // Drain the queued events that arrived during the freeze. On
    // replay they get re-delivered to natural targets in arrival
    // order (matching Xorg PlayReleasedEvents); on non-replay
    // releases (AsyncPointer / SyncPointer) we drop them — the grab
    // owner already consumed the activating press, and per-event
    // delivery semantics for "the events you held while frozen"
    // diverge once the grab unfreezes asynchronously. Holding them
    // until next press would be worse: stale events accumulate.
    let frozen_pointer_queue = if pointer_release {
        std::mem::take(&mut state.frozen_pointer_queue)
    } else {
        std::collections::VecDeque::new()
    };
    if pointer_release && state.pointer_grab_is_passive {
        state.pointer_grab = None;
        state.pointer_grab_is_passive = false;
    }

    // ReplayKeyboard / *Both: release the passive keyboard grab this
    // client holds and (for replay) re-deliver the frozen key to the
    // focus window, bypassing the grab. Mirrors Xorg ComputeFreezes.
    let frozen_keyboard = if keyboard_release {
        state.frozen_keyboard_event.take()
    } else {
        None
    };
    if keyboard_release
        && state
            .active_keyboard_grab
            .is_some_and(|g| g.owner == client_id)
        && matches!(
            state.active_keyboard_grab.map(|g| g.source),
            Some(crate::server::ActiveKeyboardGrabSource::PassiveKey { .. })
        )
    {
        state.active_keyboard_grab = None;
    }

    if pointer_replay && let Some(event) = frozen_pointer {
        // Snapshot the xid_map so we can release the immutable
        // borrow on `backend` before pointer_event_fanout_to_state
        // mutates `state`. The map is small (a few hundred entries)
        // and AllowEvents-replay is rare, so the clone is cheap
        // compared to the wire writes the fanout produces.
        let xid_map = backend.xid_map().clone();
        // is_replay=false: deliver BOTH core AND XI2 to the natural
        // target on replay. Prior to 2026-05-28 this passed
        // is_replay=true under the comment "XI2 was already
        // delivered to listeners" — that was wrong. The XI2
        // freeze-filter at pointer_fanout.rs:309-316 (cinnamon
        // aea9b0f) restricts XI2 press to the grab owner ONLY
        // during sync-passive-grab freeze; the natural target
        // never received XI2 during the freeze. Trace evidence
        // from MATE on silence (2026-05-28): marco activates
        // passive grab on the panel, AllowEvents fires, mate-panel
        // (only XI2 mask, no core mask) saw the queued release
        // but no press → menu clicks dead. Replay needs is_replay=
        // false so XI2 fanout actually runs.
        let _dropped = pointer_event_fanout_to_state(state, backend, &xid_map, event, false, false);
        // Drain freeze queue in arrival order. Same is_replay=false
        // rationale: queued events were never delivered to anyone
        // (my queue check at the top of pointer_event_fanout_to_state
        // intercepts them before any delivery), so they need full
        // core + XI2 fanout on replay.
        for queued in frozen_pointer_queue {
            let _dropped =
                pointer_event_fanout_to_state(state, backend, &xid_map, queued, false, false);
        }
    }
    if keyboard_replay && let Some(event) = frozen_keyboard {
        let _dropped = replay_frozen_key_to_focus(state, event);
    }
    Ok(RequestOutcome::Handled)
}

