    // ---------------- extract_shm_zpixmap_region ----------------
    //
    // The protocol-level byte-extraction for MIT-SHM PutImage. Until
    // 2026-05-15 the handler ignored `total_width` / `src_x` /
    // `src_y` and read a tightly-packed `src_width × src_height ×
    // bpp` block at `offset`. That happens to be correct when the
    // client sets `total == src` and `src_xy == 0` (the common
    // case), but reads garbage when the client uploads a sub-region
    // of a larger shm image. xfdesktop's thumbnail upload pattern
    // and any cairo-padded surface trigger the latter, which
    // manifests as horizontal-band corruption around the thumbnail.

    fn d32_pixel(b: u8, g: u8, r: u8, a: u8) -> [u8; 4] {
        // Wire byte order for a depth-32 ZPixmap is [B, G, R, A] —
        // see the comment in `try_vk_put_image`.
        [b, g, r, a]
    }

    #[test]
    fn extract_d32_tight_packing_returns_input() {
        // total == src, src_xy == 0 → output is exactly the input.
        let mut bytes = Vec::new();
        for y in 0..4u8 {
            for x in 0..4u8 {
                bytes.extend_from_slice(&d32_pixel(x, y, x ^ y, 0xFF));
            }
        }
        let out = extract_shm_zpixmap_region(&bytes, 0, 4, 4, 0, 0, 4, 4, 32)
            .expect("tight extraction succeeds");
        assert_eq!(out, bytes);
    }

    /// 2026-05-28 perf-cliff fix: full-frame extracts MUST return
    /// `Cow::Borrowed` (no allocation, no memcpy). On cinnamon the
    /// hot-path PutImage of the 28MB compositor stage was spending
    /// 8-10ms in the legacy per-row Vec::extend_from_slice loop.
    /// Borrowing the SHM slice directly drops it to a bounds-check.
    /// Tested both depth=24 and depth=32 at the boundary (full frame,
    /// no offset, row_bytes == src_stride) and against a partial /
    /// padded case that MUST still allocate.
    #[test]
    fn extract_full_frame_d32_returns_borrowed_slice() {
        // 8×4 full-frame extract, depth 32 → row_bytes == src_stride.
        let mut bytes = Vec::new();
        for y in 0..4u8 {
            for x in 0..8u8 {
                bytes.extend_from_slice(&d32_pixel(x, y, x ^ y, 0xFF));
            }
        }
        let out = extract_shm_zpixmap_region(&bytes, 0, 8, 4, 0, 0, 8, 4, 32)
            .expect("full-frame d32 extraction succeeds");
        assert!(
            matches!(out, std::borrow::Cow::Borrowed(_)),
            "full-frame extract must zero-copy (Cow::Borrowed)",
        );
        assert_eq!(out.as_ref(), bytes.as_slice());
    }

    #[test]
    fn extract_full_frame_d24_returns_borrowed_slice() {
        // 8×4 full-frame, depth 24 (4 bytes per pixel — same as d32).
        let mut bytes = Vec::new();
        for y in 0..4u8 {
            for x in 0..8u8 {
                bytes.extend_from_slice(&d32_pixel(x, y, x ^ y, 0xFF));
            }
        }
        let out = extract_shm_zpixmap_region(&bytes, 0, 8, 4, 0, 0, 8, 4, 24)
            .expect("full-frame d24 extraction succeeds");
        assert!(
            matches!(out, std::borrow::Cow::Borrowed(_)),
            "full-frame d24 extract must zero-copy (Cow::Borrowed)",
        );
        assert_eq!(out.as_ref(), bytes.as_slice());
    }

    #[test]
    fn extract_partial_region_returns_owned_vec() {
        // Same data but ask for a sub-region — the borrow fast path
        // MUST NOT trigger.
        let mut bytes = Vec::new();
        for y in 0..8u8 {
            for x in 0..8u8 {
                bytes.extend_from_slice(&d32_pixel(x, y, 0, 0xFF));
            }
        }
        let out = extract_shm_zpixmap_region(&bytes, 0, 8, 8, 2, 2, 4, 4, 32)
            .expect("partial extraction succeeds");
        assert!(
            matches!(out, std::borrow::Cow::Owned(_)),
            "partial extract must allocate (Cow::Owned)",
        );
    }

    #[test]
    fn extract_d8_padded_full_frame_does_not_borrow() {
        // Depth-8 with src_width=5 → src_stride=8 (pad-to-32-bit).
        // row_bytes (5) < src_stride (8) — the borrow fast path's
        // `row_bytes == src_stride` precondition excludes this so
        // the slow padding path runs.
        let bytes: Vec<u8> = (0..16).map(|i| i as u8).collect();
        let out = extract_shm_zpixmap_region(&bytes, 0, 5, 2, 0, 0, 5, 2, 8)
            .expect("padded d8 extraction succeeds");
        assert!(
            matches!(out, std::borrow::Cow::Owned(_)),
            "padded full-frame d8 must NOT borrow (per-row padding required)",
        );
    }

    #[test]
    fn extract_d32_subregion_of_larger_buffer() {
        // 8×8 total, take 4×4 at (2, 2). The handler must read row 2
        // bytes 8..24, row 3 bytes 8..24, etc. — NOT 64 contiguous
        // bytes from offset 0, which is what the pre-fix handler
        // did.
        let mut bytes = Vec::new();
        for y in 0..8u8 {
            for x in 0..8u8 {
                bytes.extend_from_slice(&d32_pixel(x, y, 0, 0xFF));
            }
        }
        let out = extract_shm_zpixmap_region(&bytes, 0, 8, 8, 2, 2, 4, 4, 32)
            .expect("subregion extraction succeeds");
        // Output must be the (2,2)..(6,6) tile, tightly packed.
        let mut want = Vec::new();
        for y in 2..6u8 {
            for x in 2..6u8 {
                want.extend_from_slice(&d32_pixel(x, y, 0, 0xFF));
            }
        }
        assert_eq!(out, want);
    }

    #[test]
    fn extract_d32_total_wider_than_src() {
        // 16×4 total, take 4×4 at (0, 0). Each src row must skip the
        // unused 12 trailing pixels of the total row.
        let mut bytes = Vec::new();
        for y in 0..4u8 {
            for x in 0..16u8 {
                bytes.extend_from_slice(&d32_pixel(x, y, 0, 0xFF));
            }
        }
        let out = extract_shm_zpixmap_region(&bytes, 0, 16, 4, 0, 0, 4, 4, 32)
            .expect("wide-total extraction succeeds");
        let mut want = Vec::new();
        for y in 0..4u8 {
            for x in 0..4u8 {
                want.extend_from_slice(&d32_pixel(x, y, 0, 0xFF));
            }
        }
        assert_eq!(out, want);
    }

    #[test]
    fn extract_honors_offset() {
        // Image starts partway into the shm segment.
        let mut bytes = vec![0xAAu8; 16];
        for y in 0..2u8 {
            for x in 0..2u8 {
                bytes.extend_from_slice(&d32_pixel(x, y, 0xFF, 0xFF));
            }
        }
        let out = extract_shm_zpixmap_region(&bytes, 16, 2, 2, 0, 0, 2, 2, 32)
            .expect("offset extraction succeeds");
        assert_eq!(out, &bytes[16..]);
    }

    #[test]
    fn extract_d8_padding_total_wider_than_src() {
        // 6-wide total → 8 bytes/row (padded to 32-bit). Take a 5×2
        // tile. Output stride is `((5 + 3) & ~3) = 8` bytes/row so
        // we get 16 bytes; first 5 are image data, next 3 are pad.
        let bytes: Vec<u8> = (0..16).map(|i| i as u8).collect();
        let out = extract_shm_zpixmap_region(&bytes, 0, 6, 2, 0, 0, 5, 2, 8)
            .expect("d8 extraction succeeds");
        assert_eq!(out.len(), 16);
        // Row 0 image bytes: 0..5 of the input; row 0 trailing pad: zero.
        assert_eq!(&out[..5], &bytes[..5]);
        assert_eq!(&out[5..8], &[0, 0, 0]);
        // Row 1 image bytes: 8..13 of the input.
        assert_eq!(&out[8..13], &bytes[8..13]);
        assert_eq!(&out[13..16], &[0, 0, 0]);
    }

    #[test]
    fn extract_d8_src_x_offset() {
        // 8-wide total → 8 bytes/row. Take a 4×1 tile at src_x=2.
        let bytes: Vec<u8> = (0..8).map(|i| i as u8).collect();
        let out = extract_shm_zpixmap_region(&bytes, 0, 8, 1, 2, 0, 4, 1, 8)
            .expect("d8 src_x extraction succeeds");
        // src_width=4 → src_stride=4 (already 32-bit aligned). Output is bytes 2..6.
        assert_eq!(out, vec![2u8, 3, 4, 5]);
    }

    #[test]
    fn extract_rejects_region_outside_total() {
        let bytes = vec![0u8; 64];
        // src_x + src_width > total_width
        assert!(extract_shm_zpixmap_region(&bytes, 0, 4, 4, 2, 0, 4, 4, 32).is_none());
        // src_y + src_height > total_height
        assert!(extract_shm_zpixmap_region(&bytes, 0, 4, 4, 0, 2, 4, 4, 32).is_none());
    }

    #[test]
    fn extract_rejects_negative_src_xy() {
        let bytes = vec![0u8; 64];
        assert!(extract_shm_zpixmap_region(&bytes, 0, 4, 4, -1, 0, 4, 4, 32).is_none());
        assert!(extract_shm_zpixmap_region(&bytes, 0, 4, 4, 0, -1, 4, 4, 32).is_none());
    }

    #[test]
    fn extract_rejects_offset_beyond_buffer() {
        let bytes = vec![0u8; 16];
        // 4×4 d32 = 64 bytes; only 16 available.
        assert!(extract_shm_zpixmap_region(&bytes, 0, 4, 4, 0, 0, 4, 4, 32).is_none());
    }

    #[test]
    fn extract_rejects_unsupported_depth() {
        let bytes = vec![0u8; 64];
        assert!(extract_shm_zpixmap_region(&bytes, 0, 4, 4, 0, 0, 4, 4, 16).is_none());
    }

    #[test]
    fn extract_d24_treats_padding_byte_as_image_data() {
        // d24 on the wire is 4 bytes per pixel like d32; the 4th
        // byte is undefined but transmitted. Extraction must copy
        // all 4 bytes — the put_image backend stamps 0xFF later.
        let mut bytes = Vec::new();
        for y in 0..2u8 {
            for x in 0..2u8 {
                bytes.extend_from_slice(&d32_pixel(x, y, 0xCC, 0x77));
            }
        }
        let out = extract_shm_zpixmap_region(&bytes, 0, 2, 2, 0, 0, 2, 2, 24)
            .expect("d24 extraction succeeds");
        assert_eq!(out, bytes);
    }

    // ---------------- end extract_shm_zpixmap_region ----------------

    #[test]
    fn redirect_invalid_mode_returns_bad_value() {
        let mut state = ServerState::new();
        let mut peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();
        // Anything outside {0, 1} is a spec violation → BadValue.
        dispatch_composite_redirect(&mut state, &mut backend, ClientId(1), 0xDEAD, 2);
        peer.set_nonblocking(true).unwrap();
        let mut buf = [0u8; 32];
        peer.read_exact(&mut buf).expect("error delivered");
        assert_eq!(buf[0], 0);
        // BAD_VALUE = 2
        assert_eq!(buf[1], 2, "expected BadValue (2), got {}", buf[1]);
        assert!(state.composite_redirects.is_empty());
    }

    // ---------------- Stage 4d gate: COW host_xid wiring ----------------
    //
    // Marco-with-compositing uses **pure PRESENT-pixmap onto COW** with zero
    // `RedirectSubwindows` / `NameWindowPixmap` calls — it repeatedly emits
    // `PRESENT::Pixmap(window=0x103 /* COW */, pixmap=client_offscreen)`.
    //
    // `process_present_pixmap` resolves both endpoints via
    // `state.resources.host_drawable_target(...)`, which returns `None` when
    // `window.host_xid` is `None`. Stage 4d allocated COW storage on the
    // backend (`KmsBackendV2.cow_id`) and registered with the scene, but
    // left `host_xid` `None` on the yserver-core resource record (seeded
    // that way at `ResourceTable::new` since the COW xid pre-exists the
    // backend-side allocation). Every `PresentPixmap → COW` therefore
    // silently fell through the `if let (Some, Some)` guard at
    // `process_request.rs:~4124` and dropped paint.
    //
    // Fix: on the GET_OVERLAY_WINDOW arm, after the backend hook lands
    // successfully, wire `host_xid = Some(0x103)` and copy root dimensions
    // onto the COW resource record. On RELEASE_OVERLAY_WINDOW, when the
    // backend signals final-release (refcount → 0), clear `host_xid` back
    // to `None` so the next GET re-wires fresh storage.
    //
    // These tests use `RecordingBackend` with its
    // `cow_next_release_is_final` knob (default `false`, opt-in to
    // simulate a final-release for the clear-host_xid test). The
    // default `Ok(false)` shape matches v1's semantics (v1 doesn't
    // track COW lifecycle).

    fn dispatch_composite_minor(
        state: &mut ServerState,
        backend: &mut dyn crate::backend::Backend,
        client_id: ClientId,
        sequence: u16,
        minor: u8,
        body: &[u8],
    ) -> RequestOutcome {
        let length_units = u32::try_from(1 + body.len().div_ceil(4)).expect("body fits");
        process_request(
            state,
            backend,
            client_id,
            SequenceNumber(sequence),
            RequestHeader {
                opcode: 144, // COMPOSITE
                data: minor,
                length_units,
            },
            body,
            None,
        )
        .unwrap()
    }

    #[test]
    fn get_overlay_window_wires_cow_host_xid() {
        // Pre-condition: COW resource record exists with host_xid = None.
        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        let cow_pre = state
            .resources
            .window(crate::resources::COMPOSITE_OVERLAY_WINDOW)
            .expect("COW record seeded at ResourceTable::new");
        assert!(
            cow_pre.host_xid.is_none(),
            "COW must start with host_xid=None — the seed in resources.rs:230 \
             must not be silently fixed without updating this oracle",
        );

        // GetOverlayWindow body: window xid (we use root, marco ignores
        // the reply's input and just trusts whatever XID we hand back).
        let mut body = vec![0u8; 4];
        body[0..4].copy_from_slice(&crate::resources::ROOT_WINDOW.0.to_le_bytes());
        dispatch_composite_minor(
            &mut state,
            &mut backend,
            ClientId(1),
            1,
            yserver_protocol::x11::composite::GET_OVERLAY_WINDOW,
            &body,
        );

        // Load-bearing assertion: after GET, host_drawable_target must
        // resolve. This is what makes PresentPixmap → COW actually paint.
        let target = state
            .resources
            .host_drawable_target(crate::resources::COMPOSITE_OVERLAY_WINDOW);
        match target {
            Some(crate::resources::HostDrawableTarget::Window {
                nested,
                host_xid,
                depth,
            }) => {
                assert_eq!(nested, crate::resources::COMPOSITE_OVERLAY_WINDOW);
                assert_eq!(
                    host_xid.as_raw(),
                    crate::resources::COMPOSITE_OVERLAY_WINDOW.0,
                    "COW host_xid must equal its protocol xid (0x103)",
                );
                assert_eq!(depth, 24, "COW is depth-24");
            }
            other => panic!(
                "host_drawable_target(COW) must resolve to Window after \
                 GetOverlayWindow — got {other:?}. Pre-fix shape returned \
                 None (host_xid still unset on the resource record), which \
                 dropped every PresentPixmap → COW.",
            ),
        }

        // Dimensions: COW should track the root extent (the backend's
        // COW storage is screen-extent per the Stage 4d plan).
        let cow = state
            .resources
            .window(crate::resources::COMPOSITE_OVERLAY_WINDOW)
            .expect("COW record");
        let root = state
            .resources
            .window(crate::resources::ROOT_WINDOW)
            .expect("ROOT record");
        assert_eq!(cow.width, root.width, "COW must match root extent");
        assert_eq!(cow.height, root.height, "COW must match root extent");
    }

    #[test]
    fn get_overlay_window_is_idempotent_across_repeated_calls() {
        // A compositor may emit GetOverlayWindow multiple times (e.g.
        // re-registration on a window-manager hand-off). The handler-
        // side wiring is idempotent: the `host_xid.is_none()` guard
        // prevents repeated allocation, repeated GETs still bump the
        // backend refcount, host_xid stays stable.
        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        let mut body = vec![0u8; 4];
        body[0..4].copy_from_slice(&crate::resources::ROOT_WINDOW.0.to_le_bytes());
        dispatch_composite_minor(
            &mut state,
            &mut backend,
            ClientId(1),
            1,
            yserver_protocol::x11::composite::GET_OVERLAY_WINDOW,
            &body,
        );
        dispatch_composite_minor(
            &mut state,
            &mut backend,
            ClientId(1),
            2,
            yserver_protocol::x11::composite::GET_OVERLAY_WINDOW,
            &body,
        );

        let cow = state
            .resources
            .window(crate::resources::COMPOSITE_OVERLAY_WINDOW)
            .expect("COW record");
        assert_eq!(
            cow.host_xid.map(crate::backend::WindowHandle::as_raw),
            Some(crate::resources::COMPOSITE_OVERLAY_WINDOW.0),
            "host_xid stays wired across repeated GETs",
        );
    }

    #[test]
    fn release_overlay_window_clears_host_xid_on_final_release() {
        // Final release (backend returns Ok(true)) must clear host_xid so
        // a subsequent GetOverlayWindow re-wires fresh storage. Otherwise
        // host_xid would alias the prior (freed) backend storage — paint
        // would land on stale GPU memory or, depending on the store's
        // detach behaviour, gap-log silently.
        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        // Wire COW via GET first.
        let mut body = vec![0u8; 4];
        body[0..4].copy_from_slice(&crate::resources::ROOT_WINDOW.0.to_le_bytes());
        dispatch_composite_minor(
            &mut state,
            &mut backend,
            ClientId(1),
            1,
            yserver_protocol::x11::composite::GET_OVERLAY_WINDOW,
            &body,
        );
        assert!(
            state
                .resources
                .window(crate::resources::COMPOSITE_OVERLAY_WINDOW)
                .and_then(|w| w.host_xid)
                .is_some(),
        );

        // Final release — backend signals "I destroyed the COW".
        backend.cow_next_release_is_final = true;
        dispatch_composite_minor(
            &mut state,
            &mut backend,
            ClientId(1),
            2,
            yserver_protocol::x11::composite::RELEASE_OVERLAY_WINDOW,
            &[],
        );
        let cow = state
            .resources
            .window(crate::resources::COMPOSITE_OVERLAY_WINDOW)
            .expect("COW record");
        assert!(
            cow.host_xid.is_none(),
            "final release (backend.Ok(true)) must clear host_xid so the \
             next GetOverlayWindow can re-wire fresh storage",
        );
    }

    #[test]
    fn release_overlay_window_keeps_host_xid_on_non_final_release() {
        // Non-final release (refcount > 0 after decrement): storage is
        // still live on the backend, host_xid must stay wired so any
        // remaining compositor's PresentPixmap → COW keeps landing.
        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        let mut body = vec![0u8; 4];
        body[0..4].copy_from_slice(&crate::resources::ROOT_WINDOW.0.to_le_bytes());
        dispatch_composite_minor(
            &mut state,
            &mut backend,
            ClientId(1),
            1,
            yserver_protocol::x11::composite::GET_OVERLAY_WINDOW,
            &body,
        );

        // Non-final release (RecordingBackend default returns Ok(false)).
        dispatch_composite_minor(
            &mut state,
            &mut backend,
            ClientId(1),
            2,
            yserver_protocol::x11::composite::RELEASE_OVERLAY_WINDOW,
            &[],
        );
        let cow = state
            .resources
            .window(crate::resources::COMPOSITE_OVERLAY_WINDOW)
            .expect("COW record");
        assert_eq!(
            cow.host_xid.map(crate::backend::WindowHandle::as_raw),
            Some(crate::resources::COMPOSITE_OVERLAY_WINDOW.0),
            "non-final release must keep host_xid wired — \
             storage is still alive on the backend",
        );
    }

    // ---------------- rotate_redirected_backing_on_resize ----------------
    //
    // Marco-with-compositing resizes the top mate-panel from 25 → 28 px
    // tall after `RedirectSubwindows(root, Manual)`. The subsequent
    // `NameWindowPixmap(panel)` must succeed against fresh storage at
    // the new size. Pre-fix v2 returned `NotFound` because the rotate
    // path allocated-then-released against an idempotent
    // `host_window_to_backing[W]` cache and freed the very pixmap it
    // had just chosen to keep. This test pins release-then-allocate
    // ORDER — flipping it back would regress the hardware smoke bug.
    #[test]
    fn rotate_redirected_backing_on_resize_releases_old_then_allocates_new() {
        use crate::backend::recording::RecordedCall;

        const WINDOW_XID: u32 = 0x0010_0001;
        const HOST_XID: u32 = 0x0040_0001;
        const OLD_BACKING: u32 = 0x0050_0001;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        // Install a top-level child of root, then prime it with a
        // pretend-existing redirected backing (the state we'd be in
        // after `RedirectSubwindows` + activation but before the
        // resize). 100x50 → resize target 100x75.
        state.resources.create_window(
            yserver_protocol::x11::ClientId(1),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 32,
                window: ResourceId(WINDOW_XID),
                parent: crate::resources::ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 50,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
            w.redirected_backing = Some(crate::resources::RedirectedBacking {
                host_pixmap: crate::backend::PixmapHandle::from_raw_for_test(OLD_BACKING),
                width: 100,
                height: 50,
                depth: 32,
            });
        }

        rotate_redirected_backing_on_resize(
            &mut state,
            &mut backend,
            None,
            ResourceId(WINDOW_XID),
            100,
            75,
        );

        let calls = backend.calls();
        // RetainBackingStorage comes first to keep OLD's storage
        // alive across the release→copy gap (see
        // `rotate_redirected_backing_retains_old_storage_across_release_then_drops_after_copy`).
        // Release must then precede Allocate so the backend's
        // idempotent `host_window_to_backing[W]` lookup misses on
        // the subsequent allocate.
        assert_eq!(
            calls[0],
            RecordedCall::RetainBackingStorage(OLD_BACKING),
            "step 1 must be RetainBackingStorage on OLD — keeps storage \
             alive across the release→copy gap so the no-alias case \
             doesn't drop the rotate copy",
        );
        assert_eq!(
            calls[1],
            RecordedCall::ReleaseRedirectedBacking(OLD_BACKING),
            "step 2 must be ReleaseRedirectedBacking on the OLD backing — \
             release-before-allocate is load-bearing (see fn doc-comment)",
        );
        assert_eq!(
            calls[2],
            RecordedCall::AllocateRedirectedBacking {
                host_window: HOST_XID,
                width: 100,
                height: 75,
                depth: 32,
            },
            "step 3 must be AllocateRedirectedBacking at the NEW size",
        );

        // Window resource now points at the freshly-allocated backing
        // (RecordingBackend hands back fresh handles per allocate).
        let backing = state
            .resources
            .window(ResourceId(WINDOW_XID))
            .and_then(|w| w.redirected_backing)
            .expect("redirected_backing repointed after rotate");
        assert_ne!(
            backing.host_pixmap.as_raw(),
            OLD_BACKING,
            "redirected_backing must point at the NEW pixmap, not the old one",
        );
        assert_eq!(backing.width, 100);
        assert_eq!(backing.height, 75);
        assert_eq!(backing.depth, 32);
    }

    // compCopyWindow analog: when a redirected window resizes, the
    // pre-existing backing's contents must be carried over into the new
    // backing for the overlap region — otherwise any compositor that
    // re-Names the post-resize backing (marco on mate-panel-top during
    // the 25→28-px grow, etc.) samples an empty buffer and the panel
    // renders without the icons that were already painted into the old
    // backing. Xorg lands this via `compReallocPixmap` (save old
    // pixmap) + `compCopyWindow` (copy_area old→new). See
    // /home/jos/Projects/xserver/composite/compalloc.c:680-712 and
    // compwindow.c:376-388.
    #[test]
    fn rotate_redirected_backing_on_resize_copies_old_contents_to_new() {
        use crate::backend::recording::RecordedCall;

        const WINDOW_XID: u32 = 0x0010_0001;
        const HOST_XID: u32 = 0x0040_0001;
        const OLD_BACKING: u32 = 0x0050_0001;
        const OLD_W: u16 = 100;
        const OLD_H: u16 = 50;
        const NEW_W: u16 = 100;
        const NEW_H: u16 = 75;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(1),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 32,
                window: ResourceId(WINDOW_XID),
                parent: crate::resources::ROOT_WINDOW,
                x: 0,
                y: 0,
                width: OLD_W,
                height: OLD_H,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
            w.redirected_backing = Some(crate::resources::RedirectedBacking {
                host_pixmap: crate::backend::PixmapHandle::from_raw_for_test(OLD_BACKING),
                width: OLD_W,
                height: OLD_H,
                depth: 32,
            });
        }

        rotate_redirected_backing_on_resize(
            &mut state,
            &mut backend,
            None,
            ResourceId(WINDOW_XID),
            NEW_W,
            NEW_H,
        );

        // NEW handle is whatever the RecordingBackend's allocate
        // handed back; pull it from the resource state.
        let new_backing = state
            .resources
            .window(ResourceId(WINDOW_XID))
            .and_then(|w| w.redirected_backing)
            .expect("redirected_backing repointed after rotate");
        let new_raw = new_backing.host_pixmap.as_raw();

        let calls = backend.calls();
        // Expected overlap = min(old, new) per dimension.
        let expected_w = OLD_W.min(NEW_W);
        let expected_h = OLD_H.min(NEW_H);
        let copy = calls.iter().find(|c| {
            matches!(
                c,
                RecordedCall::CopyArea {
                    src_host_xid,
                    dst_host_xid,
                    src_x: 0,
                    src_y: 0,
                    dst_x: 0,
                    dst_y: 0,
                    width,
                    height,
                } if *src_host_xid == OLD_BACKING
                    && *dst_host_xid == new_raw
                    && *width == expected_w
                    && *height == expected_h
            )
        });
        assert!(
            copy.is_some(),
            "expected CopyArea(OLD=0x{OLD_BACKING:x} → NEW=0x{new_raw:x}, \
             src=(0,0), dst=(0,0), {expected_w}x{expected_h}) — \
             missing the compCopyWindow analog that carries pre-resize \
             contents into the freshly-allocated backing. Calls: {calls:?}",
        );
    }

    // Storage-alive invariant for the rotate copy. Observed in HW
    // smoke (yserver-hw-mate.log 17:28:10Z) that the rotate path
    // dropped tiny 1×1 CopyAreas with `copy_area dropped — src
    // unknown` whenever OLD had no `NameWindowPixmap` aliases: the
    // existing `release_redirected_backing` decref'd alias_registry
    // to 0 → `free_pixmap` → store entry gone → `store.lookup(OLD)`
    // returned None at the copy site → silent drop.
    //
    // Fix shape: take a rotate-scoped retain on OLD's storage
    // BEFORE the release (so release's decref doesn't hit 0), drop
    // it AFTER the copy (frees storage only if no other aliases
    // hold it). This test pins the call ordering on
    // RecordingBackend; the v2-side alias_registry incref/decref
    // semantics are exercised by the v2 backend's own tests.
    #[test]
    fn rotate_redirected_backing_retains_old_storage_across_release_then_drops_after_copy() {
        use crate::backend::recording::RecordedCall;

        const WINDOW_XID: u32 = 0x0010_0001;
        const HOST_XID: u32 = 0x0040_0001;
        const OLD_BACKING: u32 = 0x0050_0001;
        const OLD_W: u16 = 1;
        const OLD_H: u16 = 1;
        const NEW_W: u16 = 1;
        const NEW_H: u16 = 1;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(1),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 32,
                window: ResourceId(WINDOW_XID),
                parent: crate::resources::ROOT_WINDOW,
                x: 0,
                y: 0,
                width: OLD_W,
                height: OLD_H,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
            w.redirected_backing = Some(crate::resources::RedirectedBacking {
                host_pixmap: crate::backend::PixmapHandle::from_raw_for_test(OLD_BACKING),
                width: OLD_W,
                height: OLD_H,
                depth: 32,
            });
        }

        rotate_redirected_backing_on_resize(
            &mut state,
            &mut backend,
            None,
            ResourceId(WINDOW_XID),
            NEW_W,
            NEW_H,
        );

        let calls = backend.calls();
        let retain_idx = calls
            .iter()
            .position(|c| matches!(c, RecordedCall::RetainBackingStorage(x) if *x == OLD_BACKING));
        let release_idx = calls.iter().position(
            |c| matches!(c, RecordedCall::ReleaseRedirectedBacking(x) if *x == OLD_BACKING),
        );
        let allocate_idx = calls.iter().position(|c| {
            matches!(c, RecordedCall::AllocateRedirectedBacking { host_window, .. } if *host_window == HOST_XID)
        });
        let copy_idx = calls.iter().position(|c| {
            matches!(c, RecordedCall::CopyArea { src_host_xid, .. } if *src_host_xid == OLD_BACKING)
        });
        let drop_idx = calls
            .iter()
            .position(|c| matches!(c, RecordedCall::DropBackingStorage(x) if *x == OLD_BACKING));

        let r = retain_idx.expect(
            "rotate must retain OLD storage before releasing — otherwise the no-alias \
             case frees storage before copy_area can read it (observed as `copy_area dropped \
             — src unknown` in HW smoke)",
        );
        let rel = release_idx.expect("rotate must still release OLD's W→B map slot");
        let a = allocate_idx.expect("rotate must allocate NEW");
        let c = copy_idx.expect("rotate must copy OLD→NEW");
        let d = drop_idx.expect(
            "rotate must drop the retain after copy — leaving storage alive forever \
             would leak the backing across every resize",
        );

        assert!(
            r < rel,
            "Retain(idx={r}) must precede Release(idx={rel}) — release's decref would \
             otherwise hit refcount=0 and free OLD's storage before copy. Calls: {calls:?}",
        );
        assert!(
            rel < a,
            "Release(idx={rel}) must precede Allocate(idx={a}) — host_window_to_backing[W] \
             idempotency would otherwise return OLD instead of allocating fresh. Calls: {calls:?}",
        );
        assert!(
            a < c,
            "Allocate(idx={a}) must precede Copy(idx={c}) — copy needs NEW as destination. \
             Calls: {calls:?}",
        );
        assert!(
            c < d,
            "Copy(idx={c}) must precede Drop(idx={d}) — dropping the retain before the copy \
             defeats the purpose of taking it. Calls: {calls:?}",
        );
    }

    /// Manual-mode redirect removes W from the normal scene and keeps
    /// B as an off-screen compositor source. B must not become a scene
    /// participant, or the scene path can double-present redirected
    /// client content behind/above the compositor's output surface.
    #[test]
    fn manual_redirect_keeps_window_out_of_scene() {
        use crate::backend::recording::RecordedCall;

        const WINDOW_XID: u32 = 0x0010_0001;
        const HOST_XID: u32 = 0x0040_0001;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        // Install a top-level child of root (the soon-to-be-Manual-
        // redirected window). Use real CreateWindow flow so the
        // resource record carries width/height/depth that
        // `activate_redirect_backing_for` snapshots.
        state.resources.create_window(
            yserver_protocol::x11::ClientId(1),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: crate::resources::ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 50,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
        }
        state.composite_redirects.insert(
            (ResourceId(WINDOW_XID), false),
            crate::server::RedirectRecord {
                mode: crate::server::CompositeRedirectMode::Manual,
                owner: yserver_protocol::x11::ClientId(1),
            },
        );

        activate_redirect_backing_for(
            &mut state,
            &mut backend,
            None,
            ResourceId(WINDOW_XID),
            crate::server::CompositeRedirectMode::Manual,
        );

        // Window participation: Manual → false (the external
        // compositor owns the window's presentation). The paired
        // assertion that B *is* scene-participating lives in
        // `manual_redirect_marks_backing_scene_participating_so_paints_emit_damage`.
        let calls = backend.calls();
        assert!(
            calls.iter().any(|c| matches!(
                c,
                RecordedCall::SetWindowSceneParticipation {
                    host_window,
                    participating: false,
                } if *host_window == HOST_XID
            )),
            "expected SetWindowSceneParticipation(W, false) for Manual mode; got {calls:?}",
        );
    }

    /// Manual-redirected backing must have scene_participating=true so
    /// the v2 scene's damage harvest sees paints into it.
    ///
    /// Post-`6ffd370` the scene walk emits the Manual-redirected window
    /// at its own coords but samples storage from the backing via
    /// `redirected_target` indirection. `store.damage()` is gated on
    /// the *target's* `scene_participating` — if the backing is marked
    /// non-participating, every paint into it silently drops its scene
    /// damage. Buffer-age clipped compose then never repaints the
    /// affected region, and the BO retains whatever was in it the last
    /// time it was flipped. Symptom: window content invisible except
    /// where cursor damage happens to overlap the window's rect.
    #[test]
    fn manual_redirect_marks_backing_scene_participating_so_paints_emit_damage() {
        use crate::backend::recording::RecordedCall;

        const WINDOW_XID: u32 = 0x0010_0001;
        const HOST_XID: u32 = 0x0040_0001;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, 1);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(1),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: crate::resources::ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 50,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
        }
        state.composite_redirects.insert(
            (ResourceId(WINDOW_XID), false),
            crate::server::RedirectRecord {
                mode: crate::server::CompositeRedirectMode::Manual,
                owner: yserver_protocol::x11::ClientId(1),
            },
        );

        activate_redirect_backing_for(
            &mut state,
            &mut backend,
            None,
            ResourceId(WINDOW_XID),
            crate::server::CompositeRedirectMode::Manual,
        );

        let calls = backend.calls();
        assert!(
            calls.iter().any(|c| matches!(
                c,
                RecordedCall::SetBackingSceneParticipation {
                    participating: true,
                    ..
                }
            )),
            "expected SetBackingSceneParticipation(B, true) for Manual mode so the \
             scene's redirected_target damage-peek sees paints; got {calls:?}",
        );
    }

    /// Mapping a Manual-redirected window must not leave it visible
    /// in the normal scene. The map path temporarily flips the
    /// storage on, then the redirect-mode reapply must force it back
    /// off.
    #[test]
    fn map_window_reapplies_manual_redirect_scene_participation() {
        use crate::backend::recording::RecordedCall;

        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0002;
        const HOST_XID: u32 = 0x0040_0002;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: crate::resources::ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 50,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
        }
        state.composite_redirects.insert(
            (ResourceId(WINDOW_XID), false),
            crate::server::RedirectRecord {
                mode: crate::server::CompositeRedirectMode::Manual,
                owner: yserver_protocol::x11::ClientId(CLIENT_ID),
            },
        );

        activate_redirect_backing_for(
            &mut state,
            &mut backend,
            None,
            ResourceId(WINDOW_XID),
            crate::server::CompositeRedirectMode::Manual,
        );
        let before = backend.calls().len();

        let mut body = Vec::with_capacity(4);
        body.extend_from_slice(&WINDOW_XID.to_le_bytes());
        handle_map_window(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            &body,
        )
        .expect("handle_map_window");

        let calls = &backend.calls()[before..];
        assert!(
            calls.iter().any(|c| matches!(
                c,
                RecordedCall::SetWindowSceneParticipation {
                    host_window,
                    participating: false,
                } if *host_window == HOST_XID
            )),
            "mapping a Manual-redirected window must reassert scene_participating=false; got {calls:?}",
        );
        assert!(
            !calls.iter().any(|c| matches!(
                c,
                RecordedCall::SetWindowSceneParticipation {
                    host_window,
                    participating: true,
                } if *host_window == HOST_XID
            )),
            "mapping a Manual-redirected window must not leave it scene_participating=true; got {calls:?}",
        );
    }

    /// Audit #11 regression — when a window maps, server-background
    /// paint fills the window's storage but no `DamageNotify` fires
    /// for the affected region. Compositors that subscribe to
    /// `XDamageCreate(window)` (marco-with-compositing, picom) miss
    /// the first frame and the window stays invisible on COW until
    /// the next paint into it. Symptom: override-redirect popup
    /// menus, mate-panel system-tray icons (`nm-applet`) don't show
    /// when a compositor is active and v2 routes the visible output
    /// through `Present::Pixmap → COW`.
    ///
    /// Oracle: a `DamageObject` subscribed to a freshly-created
    /// window must accumulate damage rects covering the window's
    /// full extent after `handle_map_window` returns.
    #[test]
    fn map_window_emits_damage_on_window_extent() {
        use crate::server::DamageObject;

        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0010;
        const HOST_XID: u32 = 0x0040_0010;
        const DAMAGE_ID: u32 = 0x0080_0010;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: crate::resources::ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 200,
                height: 80,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
        }

        // Compositor subscribes via `XDamageCreate(window)`. Pin the
        // pre-state explicitly: no rects accumulated yet.
        state.damage_objects.insert(
            DAMAGE_ID,
            DamageObject {
                owner: ClientId(CLIENT_ID),
                drawable: ResourceId(WINDOW_XID),
                level: 0,
                rects: Vec::new(),
                pending_notify_fired: false,
                last_reported_geometry: None,
            },
        );

        let mut body = Vec::with_capacity(4);
        body.extend_from_slice(&WINDOW_XID.to_le_bytes());
        handle_map_window(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            &body,
        )
        .expect("handle_map_window");

        let damage = state
            .damage_objects
            .get(&DAMAGE_ID)
            .expect("damage_object survived map");
        assert!(
            !damage.rects.is_empty(),
            "MapWindow must fire damage on the window's extent so a \
             subscribed compositor repaints the new region into its \
             offscreen — pre-fix this is empty and the compositor \
             never sees the newly-mapped popup / tray icon / window",
        );
    }

    /// Per X11 protocol spec: "If the window is already mapped, this
    /// request has no effect." brisk-menu (Ubuntu MATE's standalone
    /// applications popup) pounds `MapWindow` at ~50 Hz on its
    /// already-viewable override-redirect popup via GTK3's
    /// `gtk_window_present`/`XMapRaised` loop. Pre-fix every redundant
    /// MapWindow re-emitted MapNotify → Expose → full-extent damage,
    /// triggering Marco to issue `COMPOSITE::NameWindowPixmap` and a
    /// full recomposite of the popup ~50× per second — visible as
    /// menu flicker on the COW-authoritative KMS scene path.
    #[test]
    fn map_window_on_already_mapped_window_is_no_op() {
        use crate::server::DamageObject;
        use std::io::Read;

        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0014;
        const HOST_XID: u32 = 0x0040_0014;
        const DAMAGE_ID: u32 = 0x0080_0014;

        let mut state = ServerState::new();
        let mut peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 200,
                height: 80,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
        }

        // Marco-like subscriber: SubstructureNotify on root +
        // XDamageCreate on the new window.
        state
            .clients
            .get_mut(&CLIENT_ID)
            .unwrap()
            .event_masks
            .insert(ROOT_WINDOW, 0x0008_0000);
        state.damage_objects.insert(
            DAMAGE_ID,
            DamageObject {
                owner: ClientId(CLIENT_ID),
                drawable: ResourceId(WINDOW_XID),
                level: 0,
                rects: Vec::new(),
                pending_notify_fired: false,
                last_reported_geometry: None,
            },
        );

        let mut body = Vec::with_capacity(4);
        body.extend_from_slice(&WINDOW_XID.to_le_bytes());

        // First map: genuine transition Unmapped → Viewable. Should
        // emit MapNotify + accumulate damage.
        handle_map_window(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            &body,
        )
        .expect("handle_map_window first");

        peer.set_nonblocking(true).unwrap();
        let mut tmp = [0u8; 1024];
        let mut first_wire = Vec::new();
        loop {
            match peer.read(&mut tmp) {
                Ok(0) => break,
                Ok(n) => first_wire.extend_from_slice(&tmp[..n]),
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => break,
                Err(_) => break,
            }
        }
        let first_map_notifies = first_wire
            .chunks_exact(32)
            .filter(|chunk| chunk[0] & 0x7f == 19)
            .count();
        assert!(
            first_map_notifies >= 1,
            "first MapWindow on an unmapped window must emit MapNotify",
        );
        let first_rect_count = state
            .damage_objects
            .get(&DAMAGE_ID)
            .expect("damage object")
            .rects
            .len();
        assert!(
            first_rect_count > 0,
            "first MapWindow must accumulate damage on the window extent",
        );

        // Second map on the now-already-Viewable window. Per spec this
        // is a no-op: no MapNotify, no extra damage rects.
        handle_map_window(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(2),
            &body,
        )
        .expect("handle_map_window second");

        let mut second_wire = Vec::new();
        loop {
            match peer.read(&mut tmp) {
                Ok(0) => break,
                Ok(n) => second_wire.extend_from_slice(&tmp[..n]),
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => break,
                Err(_) => break,
            }
        }
        let second_map_notifies = second_wire
            .chunks_exact(32)
            .filter(|chunk| chunk[0] & 0x7f == 19)
            .count();
        assert_eq!(
            second_map_notifies, 0,
            "MapWindow on an already-mapped window must NOT re-emit \
             MapNotify — repeated MapNotifies cause Marco to re-issue \
             COMPOSITE::NameWindowPixmap and full recomposite on every \
             redundant map (visible as brisk-menu flicker on KMS).",
        );
        let second_rect_count = state
            .damage_objects
            .get(&DAMAGE_ID)
            .expect("damage object")
            .rects
            .len();
        assert_eq!(
            second_rect_count, first_rect_count,
            "MapWindow on an already-mapped window must NOT accumulate \
             additional damage — full-extent damage on every redundant \
             call is what drives the recompositing flicker storm.",
        );
    }

    /// Per X11 protocol: `cursor = None` (resource id 0) on
    /// ChangeWindowAttributes(CWCursor) means "clear this window's
    /// cursor so the effective cursor inherits from the parent
    /// chain". Pre-fix the handler short-circuited because
    /// `resources.cursor_host_xid(ResourceId(0))` returns `None` and
    /// the `(Some, Some)` match below dropped the call — marco
    /// resets its frame's cursor via `XDefineCursor(frame, None)`
    /// when the pointer moves off the resize edge into the frame
    /// interior, and that reset never propagated to the backend
    /// (resize cursor sprite stayed visible until the pointer left
    /// the top-level frame entirely). Matches Xorg
    /// `dix/window.c:1487-1491`.
    #[test]
    fn cwa_cursor_none_propagates_define_cursor_zero_to_backend() {
        use crate::backend::recording::RecordedCall;

        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0020;
        const HOST_XID: u32 = 0x0040_0020;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 200,
                height: 80,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
        }

        // CWA body: window xid (4) + value_mask (4) + values.
        // CWCursor is bit 14 (mask = 0x4000); value = 0 means
        // X11 None.
        let mut body = Vec::with_capacity(12);
        body.extend_from_slice(&WINDOW_XID.to_le_bytes());
        body.extend_from_slice(&0x4000u32.to_le_bytes());
        body.extend_from_slice(&0u32.to_le_bytes());

        handle_change_window_attributes(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            &body,
        )
        .expect("handle_change_window_attributes");

        let define_cursor_calls: Vec<_> = backend
            .calls()
            .into_iter()
            .filter(|c| matches!(c, RecordedCall::DefineCursor { .. }))
            .collect();
        assert_eq!(
            define_cursor_calls,
            vec![RecordedCall::DefineCursor {
                host_window_xid: HOST_XID,
                cursor_host_xid: 0,
            }],
            "CWA with CWCursor + value=0 must invoke \
             `backend.define_cursor(window, 0)` so the backend clears \
             its per-window cursor slot and refreshes the effective \
             cursor. Pre-fix this dropped silently, leaving stale \
             cursor state (marco's resize-frame XDefineCursor(frame, \
             None) reset on edge→interior transitions had no effect).",
        );
    }

    /// A `ChangeWindowAttributes` that only changes the cursor (or any
    /// other non-event-mask attribute) must NOT move the input focus.
    /// In X11 focus changes only via `SetInputFocus` / grabs, never CWA.
    ///
    /// Regression (the evince / GTK4 titlebar-drag freeze): during a
    /// `_NET_WM_MOVERESIZE` move, muffin sets the "fleur" move cursor on
    /// its guard window via a cursor-only CWA. The handler promoted
    /// keyboard focus to any "focus-wanting" (viewable + key-selecting)
    /// window on *any* CWA, so focus was stolen to the guard window. The
    /// app's next `SetInputFocus` to its own child was then computed from
    /// that unrelated prev focus -> `FocusOut(detail=Nonlinear)` -> GTK4
    /// backdrop (greyed CSD buttons) and the drag collapsed.
    #[test]
    fn cursor_only_cwa_does_not_steal_keyboard_focus() {
        const CLIENT_ID: u32 = 1;
        const GUARD_XID: u32 = 0x0010_0011; // muffin's guard window
        const FOCUSED_XID: u32 = 0x0010_0007; // the real focus window

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        for xid in [GUARD_XID, FOCUSED_XID] {
            state.resources.create_window(
                yserver_protocol::x11::ClientId(CLIENT_ID),
                yserver_protocol::x11::CreateWindowRequest {
                    depth: 24,
                    window: ResourceId(xid),
                    parent: ROOT_WINDOW,
                    x: 0,
                    y: 0,
                    width: 100,
                    height: 100,
                    border_width: 0,
                    class: 1,
                    visual: crate::resources::ROOT_VISUAL,
                    ..Default::default()
                },
            );
            let _ = state.resources.map_window(ResourceId(xid));
        }
        // Guard window is viewable and selects key events, so
        // `window_wants_keyboard_focus` would return true for it.
        state
            .clients
            .get_mut(&CLIENT_ID)
            .expect("client")
            .event_masks
            .insert(ResourceId(GUARD_XID), 0x1); // KeyPress

        // Establish the real focus on FOCUSED_XID before the CWA.
        for c in state.clients.values_mut() {
            c.focused_window = ResourceId(FOCUSED_XID);
        }

        // Cursor-only CWA on the guard window: CWCursor (bit 14 =
        // 0x4000), value 0 = None. No event-mask change.
        let mut body = Vec::with_capacity(12);
        body.extend_from_slice(&GUARD_XID.to_le_bytes());
        body.extend_from_slice(&0x4000u32.to_le_bytes());
        body.extend_from_slice(&0u32.to_le_bytes());

        handle_change_window_attributes(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            &body,
        )
        .expect("handle_change_window_attributes");

        assert_eq!(
            state
                .clients
                .get(&CLIENT_ID)
                .expect("client")
                .focused_window,
            ResourceId(FOCUSED_XID),
            "a cursor-only ChangeWindowAttributes must not promote keyboard \
             focus to the target window; focus must stay where SetInputFocus \
             put it",
        );
    }

    /// GTK4 (gnome-text-editor, modern GTK apps) sets per-widget
    /// cursors through XInput2's `XIChangeCursor` (opcode 42), not
    /// core X11's `XDefineCursor`. Pre-fix the handler was a logging
    /// no-op, so the I-beam cursor over a text widget never reached
    /// the backend and the area kept showing the default arrow.
    /// Treat it as `XDefineCursor` (per-device cursors aren't routed
    /// yet; a single effective cursor on the window matches what
    /// `AllMasterDevices`-style calls produce in practice).
    #[test]
    fn xi_change_cursor_propagates_define_cursor_to_backend() {
        use crate::backend::recording::RecordedCall;

        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0030;
        const HOST_XID: u32 = 0x0040_0030;
        const CURSOR_XID: u32 = 0x0090_0001;
        const CURSOR_HOST_XID: u32 = 0x00a0_0001;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 200,
                height: 80,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
        }
        state
            .resources
            .create_cursor(ClientId(CLIENT_ID), ResourceId(CURSOR_XID));
        state.resources.set_cursor_host_xid(
            ResourceId(CURSOR_XID),
            crate::backend::CursorHandle::from_raw_panicking(CURSOR_HOST_XID),
        );

        // XIChangeCursor body: window(4), cursor(4), deviceid(2), pad(2).
        let mut body = Vec::with_capacity(12);
        body.extend_from_slice(&WINDOW_XID.to_le_bytes());
        body.extend_from_slice(&CURSOR_XID.to_le_bytes());
        body.extend_from_slice(&0u16.to_le_bytes());
        body.extend_from_slice(&[0u8; 2]);

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131, // doesn't matter — dispatcher is bypassed
            data: 42,    // XIChangeCursor minor
            length_units: 3,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("handle_xi2_request");

        let define_cursor_calls: Vec<_> = backend
            .calls()
            .into_iter()
            .filter(|c| matches!(c, RecordedCall::DefineCursor { .. }))
            .collect();
        assert_eq!(
            define_cursor_calls,
            vec![RecordedCall::DefineCursor {
                host_window_xid: HOST_XID,
                cursor_host_xid: CURSOR_HOST_XID,
            }],
            "XIChangeCursor must propagate to `backend.define_cursor` \
             so GTK4's per-widget cursor (I-beam on text areas, etc.) \
             becomes effective. Pre-fix the handler was a logging \
             no-op — gnome-text-editor and other GTK4 apps kept the \
             default arrow over text widgets.",
        );

        // cursor = None (xid 0) clears the per-window cursor.
        let mut body_none = Vec::with_capacity(12);
        body_none.extend_from_slice(&WINDOW_XID.to_le_bytes());
        body_none.extend_from_slice(&0u32.to_le_bytes());
        body_none.extend_from_slice(&0u16.to_le_bytes());
        body_none.extend_from_slice(&[0u8; 2]);

        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(2),
            header,
            &body_none,
        )
        .expect("handle_xi2_request none");

        let define_cursor_calls: Vec<_> = backend
            .calls()
            .into_iter()
            .filter(|c| matches!(c, RecordedCall::DefineCursor { .. }))
            .collect();
        assert_eq!(
            define_cursor_calls,
            vec![
                RecordedCall::DefineCursor {
                    host_window_xid: HOST_XID,
                    cursor_host_xid: CURSOR_HOST_XID,
                },
                RecordedCall::DefineCursor {
                    host_window_xid: HOST_XID,
                    cursor_host_xid: 0,
                },
            ],
            "XIChangeCursor with cursor=None (xid 0) must invoke \
             `backend.define_cursor(window, 0)` — same X11 None \
             semantics as the CWA cursor path.",
        );
    }

    /// `XIGrabDevice` must wire into the existing core X11 grab
    /// state (`state.pointer_grab` + `state.active_pointer_grab` for
    /// the master pointer, `state.active_keyboard_grab` for the
    /// master keyboard) so the pointer/key fanout's
    /// `active_grab_target` routing kicks in. Pre-fix the handler
    /// was a no-op that just sent Success — GTK thought it owned
    /// the device but events still went to whatever window the
    /// pointer was over, so popups dismissed on the first stray
    /// motion and `gtk_window_present` looped re-mapping at ~50 Hz.
    #[test]
    fn xi_grab_device_sets_active_grab_state() {
        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0050;
        const CURSOR_XID: u32 = 0x0090_0050;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        // Pointer grab (deviceid=2) — XIGrabDevice body: window(4)
        // time(4) cursor(4) deviceid(2) mode(1) paired(1)
        // owner_events(1) pad(1) mask_len(2) ...
        let mut body = Vec::with_capacity(24);
        body.extend_from_slice(&WINDOW_XID.to_le_bytes()); // window
        body.extend_from_slice(&0u32.to_le_bytes()); // time
        body.extend_from_slice(&CURSOR_XID.to_le_bytes()); // cursor
        body.extend_from_slice(&2u16.to_le_bytes()); // deviceid (pointer)
        body.extend_from_slice(&[1, 1, 1, 0]); // mode async, paired async, owner_events=1, pad
        body.extend_from_slice(&0u16.to_le_bytes()); // mask_len
        body.extend_from_slice(&[0u8; 2]); // pad

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 51, // XIGrabDevice
            length_units: 7,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("XIGrabDevice pointer");

        assert_eq!(
            state.pointer_grab,
            Some((ClientId(CLIENT_ID), ResourceId(WINDOW_XID))),
            "XIGrabDevice(pointer) must set state.pointer_grab so \
             pointer_fanout's active_grab_target redirect kicks in",
        );
        assert!(!state.pointer_grab_is_passive);
        let active = state.active_pointer_grab.expect("active_pointer_grab set");
        assert_eq!(active.owner, ClientId(CLIENT_ID));
        assert_eq!(active.grab_window, ResourceId(WINDOW_XID));
        assert_eq!(active.cursor, ResourceId(CURSOR_XID));

        // Keyboard grab (deviceid=3) — same wire format.
        let mut body_kbd = Vec::with_capacity(24);
        body_kbd.extend_from_slice(&WINDOW_XID.to_le_bytes());
        body_kbd.extend_from_slice(&0u32.to_le_bytes());
        body_kbd.extend_from_slice(&0u32.to_le_bytes());
        body_kbd.extend_from_slice(&3u16.to_le_bytes()); // keyboard
        body_kbd.extend_from_slice(&[1, 1, 1, 0]);
        body_kbd.extend_from_slice(&0u16.to_le_bytes());
        body_kbd.extend_from_slice(&[0u8; 2]);
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(2),
            header,
            &body_kbd,
        )
        .expect("XIGrabDevice keyboard");
        let kgrab = state
            .active_keyboard_grab
            .expect("active_keyboard_grab set");
        assert_eq!(kgrab.owner, ClientId(CLIENT_ID));
        assert_eq!(kgrab.grab_window, ResourceId(WINDOW_XID));

        // Ungrab both — XIUngrabDevice body: time(4) deviceid(2) pad(2).
        let ungrab_header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 52,
            length_units: 2,
        };
        let mut ungrab_p = Vec::with_capacity(8);
        ungrab_p.extend_from_slice(&0u32.to_le_bytes()); // time
        ungrab_p.extend_from_slice(&2u16.to_le_bytes()); // pointer
        ungrab_p.extend_from_slice(&[0u8; 2]);
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(3),
            ungrab_header,
            &ungrab_p,
        )
        .expect("XIUngrabDevice pointer");
        assert!(state.pointer_grab.is_none(), "pointer grab cleared");
        assert!(state.active_pointer_grab.is_none());

        let mut ungrab_k = Vec::with_capacity(8);
        ungrab_k.extend_from_slice(&0u32.to_le_bytes());
        ungrab_k.extend_from_slice(&3u16.to_le_bytes());
        ungrab_k.extend_from_slice(&[0u8; 2]);
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(4),
            ungrab_header,
            &ungrab_k,
        )
        .expect("XIUngrabDevice keyboard");
        assert!(
            state.active_keyboard_grab.is_none(),
            "keyboard grab cleared"
        );
    }

    /// On `XIGrabDevice` activation, Xorg synthesises an XI2 crossing
    /// event (`XI_Enter`(7) for pointer / `XI_FocusIn`(9) for keyboard)
    /// with `mode=NotifyGrab`(1) and `detail=NotifyNonlinear`(3) and
    /// delivers it to the grab requester. Without these events, GTK3
    /// popup state machines never engage their hover/click tracking —
    /// the menu is visible but items don't highlight or activate.
    /// Captured in `mate-xorg.xtrace` (Xi/exevents.c::ActivatePointer
    /// Grab / ActivateKeyboardGrab). On `XIUngrabDevice` the symmetric
    /// `mode=NotifyUngrab`(2) crossings fire.
    #[test]
    fn xi_grab_device_emits_grab_activation_crossings() {
        use std::io::Read;

        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0060;
        const HOST_XID: u32 = 0x0040_0060;

        let mut state = ServerState::new();
        let mut peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            yserver_protocol::x11::ClientId(CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: ROOT_WINDOW,
                x: 100,
                y: 200,
                width: 300,
                height: 200,
                border_width: 0,
                class: 1,
                visual: crate::resources::ROOT_VISUAL,
                ..Default::default()
            },
        );
        {
            let w = state
                .resources
                .window_mut(ResourceId(WINDOW_XID))
                .expect("window installed");
            w.host_xid = Some(crate::backend::WindowHandle::from_raw_for_test(HOST_XID));
        }
        let _ = state.resources.map_window(ResourceId(WINDOW_XID));

        // XIGrabDevice pointer.
        let mut body = Vec::with_capacity(24);
        body.extend_from_slice(&WINDOW_XID.to_le_bytes());
        body.extend_from_slice(&0u32.to_le_bytes()); // time
        body.extend_from_slice(&0u32.to_le_bytes()); // cursor
        body.extend_from_slice(&2u16.to_le_bytes()); // deviceid
        body.extend_from_slice(&[1, 1, 1, 0]);
        body.extend_from_slice(&0u16.to_le_bytes()); // mask_len
        body.extend_from_slice(&[0u8; 2]);
        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 51,
            length_units: 7,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("XIGrabDevice");

        // Drain wire and look for the synthesised XI2 Enter event:
        //   byte 0: 35 (GenericEvent)
        //   byte 1: 137 (XInputExtension major)
        //   bytes 8-9: evtype = 7 (XI_Enter)
        //   byte 12: mode = 1 (NotifyGrab)
        //   byte 13: detail = 3 (NotifyNonlinear)
        peer.set_nonblocking(true).unwrap();
        let mut wire = Vec::new();
        let mut tmp = [0u8; 4096];
        loop {
            match peer.read(&mut tmp) {
                Ok(0) => break,
                Ok(n) => wire.extend_from_slice(&tmp[..n]),
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => break,
                Err(_) => break,
            }
        }
        // Wire contains both the 32-byte XIGrabDevice reply and the
        // synthesised XI2 GenericEvent (76 bytes). Order may vary —
        // scan for the GenericEvent signature: type=35, major=137,
        // evtype=7 (XI_Enter).
        let crossing_offset = (0..wire.len().saturating_sub(76))
            .find(|&i| {
                wire[i] == 35
                    && wire[i + 1] == 137
                    && u16::from_le_bytes([wire[i + 8], wire[i + 9]]) == 7
            })
            .unwrap_or_else(|| {
                panic!(
                    "no XI_Enter GenericEvent found in {} wire bytes: {:?}",
                    wire.len(),
                    &wire[..wire.len().min(140)],
                )
            });
        let crossing = &wire[crossing_offset..crossing_offset + 76];
        // Crossing event byte layout (from encode_xi2_crossing_event):
        //   0:type=35, 1:major, 2..4:seq, 4..8:length, 8..10:evtype,
        //   10..12:deviceid, 12..16:time, 16..18:sourceid, 18:mode,
        //   19:detail, 20..24:root, 24..28:event, ...
        assert_eq!(crossing[18], 1, "mode = NotifyGrab");
        assert_eq!(crossing[19], 3, "detail = NotifyNonlinear");
        let event_window =
            u32::from_le_bytes([crossing[24], crossing[25], crossing[26], crossing[27]]);
        assert_eq!(event_window, WINDOW_XID);
    }

    /// `XIPassiveGrabDevice` with grab_type=Button(0) installs entries
    /// in `state.button_grabs`; grab_type=Keycode(1) installs entries
    /// in `state.key_grabs`. One entry per modifier (or one entry with
    /// modifiers=0 when num_modifiers=0). `XIPassiveUngrabDevice`
    /// removes matching entries.
    #[test]
    fn xi_passive_grab_device_pushes_button_and_key_grabs() {
        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0051;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        // Helper to build XIPassiveGrabDevice body per
        // `xXIPassiveGrabDeviceReq` in X11/extensions/XI2proto.h:
        // time, grab_window, cursor, detail, deviceid, num_modifiers,
        // mask_len, grab_type, grab_mode, paired_device_mode,
        // owner_events, pad1, mask, modifiers.
        fn build_body(window: u32, detail: u32, grab_type: u8, modifiers: &[u32]) -> Vec<u8> {
            #[allow(clippy::cast_possible_truncation)]
            let num_modifiers = modifiers.len() as u16;
            let mut b = Vec::with_capacity(28 + modifiers.len() * 4);
            b.extend_from_slice(&0u32.to_le_bytes()); // time
            b.extend_from_slice(&window.to_le_bytes());
            b.extend_from_slice(&0u32.to_le_bytes()); // cursor
            b.extend_from_slice(&detail.to_le_bytes());
            b.extend_from_slice(&2u16.to_le_bytes()); // deviceid (pointer; harmless for keycode)
            b.extend_from_slice(&num_modifiers.to_le_bytes());
            b.extend_from_slice(&0u16.to_le_bytes()); // mask_len
            b.push(grab_type);
            b.push(1); // grab_mode async
            b.push(1); // paired async
            b.push(0); // owner_events
            b.extend_from_slice(&0u16.to_le_bytes()); // pad1
            for m in modifiers {
                b.extend_from_slice(&m.to_le_bytes());
            }
            b
        }
        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 54,
            length_units: 6,
        };

        // Button grab on button 3 with modifiers [0, ControlMask(4)].
        let body = build_body(WINDOW_XID, 3, 0, &[0, 4]);
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("button grab");
        assert_eq!(state.button_grabs.len(), 2, "one grab per modifier");
        assert!(
            state
                .button_grabs
                .iter()
                .any(|g| g.button == 3 && g.modifiers == 0)
        );
        assert!(
            state
                .button_grabs
                .iter()
                .any(|g| g.button == 3 && g.modifiers == 4)
        );

        // Key grab on keycode 67 (F1) with no modifiers → single entry
        // with modifier-mask 0.
        let body = build_body(WINDOW_XID, 67, 1, &[]);
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(2),
            header,
            &body,
        )
        .expect("key grab");
        assert_eq!(state.key_grabs.len(), 1);
        assert_eq!(state.key_grabs[0].keycode, 67);
        assert_eq!(state.key_grabs[0].modifiers, 0);

        // XI2 "Any" modifier (bit 31) → core X11 AnyModifier (0x8000).
        let body = build_body(WINDOW_XID, 1, 0, &[0x8000_0000]);
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(3),
            header,
            &body,
        )
        .expect("any-modifier grab");
        assert!(
            state
                .button_grabs
                .iter()
                .any(|g| g.button == 1 && g.modifiers == 0x8000),
            "XI2 Any (bit 31) maps to core X11 AnyModifier 0x8000",
        );

        // XIPassiveUngrabDevice — body: window(4) detail(4) deviceid(2)
        // num_modifiers(2) grab_type(1) pad(3) modifiers.
        fn build_ungrab_body(
            window: u32,
            detail: u32,
            grab_type: u8,
            modifiers: &[u32],
        ) -> Vec<u8> {
            #[allow(clippy::cast_possible_truncation)]
            let num_modifiers = modifiers.len() as u16;
            let mut b = Vec::with_capacity(16 + modifiers.len() * 4);
            b.extend_from_slice(&window.to_le_bytes());
            b.extend_from_slice(&detail.to_le_bytes());
            b.extend_from_slice(&2u16.to_le_bytes()); // deviceid
            b.extend_from_slice(&num_modifiers.to_le_bytes());
            b.push(grab_type);
            b.extend_from_slice(&[0u8; 3]);
            for m in modifiers {
                b.extend_from_slice(&m.to_le_bytes());
            }
            b
        }
        let ungrab_header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 55,
            length_units: 4,
        };
        let body = build_ungrab_body(WINDOW_XID, 3, 0, &[0, 4]);
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(4),
            ungrab_header,
            &body,
        )
        .expect("button ungrab");
        assert!(
            !state
                .button_grabs
                .iter()
                .any(|g| g.button == 3 && (g.modifiers == 0 || g.modifiers == 4)),
            "ungrab removes the matching button+modifier entries",
        );
        // AnyModifier grab still present (we didn't ungrab it).
        assert!(
            state
                .button_grabs
                .iter()
                .any(|g| g.button == 1 && g.modifiers == 0x8000)
        );
    }

    /// Regression test for the XIPassiveGrabDevice field-offset bug.
    /// `mask_len` and `grab_type` were swapped: a real client (muffin,
    /// xfwm4) sending mask_len=2 + grab_type=Keycode(1) was mis-parsed
    /// as grab_type=Enter(2), silently dropping every keyboard
    /// accelerator. The body here matches `xXIPassiveGrabDeviceReq`
    /// in `X11/extensions/XI2proto.h` byte-for-byte with mask_len=2,
    /// which is what real WM clients send.
    #[test]
    fn xi_passive_grab_device_keycode_with_xi2_mask() {
        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0010_0051;
        const KEYCODE: u32 = 116;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        // Spec-shaped body with mask_len=2 (two 4-byte mask words,
        // matching what muffin emits for XI device-event masks).
        let mut body = Vec::with_capacity(28 + 8 + 4);
        body.extend_from_slice(&0u32.to_le_bytes()); // time
        body.extend_from_slice(&WINDOW_XID.to_le_bytes()); // grab_window
        body.extend_from_slice(&0u32.to_le_bytes()); // cursor
        body.extend_from_slice(&KEYCODE.to_le_bytes()); // detail
        body.extend_from_slice(&3u16.to_le_bytes()); // deviceid (keyboard)
        body.extend_from_slice(&1u16.to_le_bytes()); // num_modifiers
        body.extend_from_slice(&2u16.to_le_bytes()); // mask_len = 2
        body.push(1); // grab_type = Keycode
        body.push(1); // grab_mode async
        body.push(1); // paired async
        body.push(0); // owner_events
        body.extend_from_slice(&0u16.to_le_bytes()); // pad1
        body.extend_from_slice(&[0u8; 8]); // mask (2 words)
        body.extend_from_slice(&0u32.to_le_bytes()); // modifier 0

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 54,
            length_units: 10,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("keycode grab with mask");

        assert_eq!(
            state.key_grabs.len(),
            1,
            "Keycode grab must be recorded — bug was misclassifying \
             as grab_type=Enter due to swapped mask_len/grab_type"
        );
        #[allow(clippy::cast_possible_truncation)]
        let expected_kc = KEYCODE as u8;
        assert_eq!(state.key_grabs[0].keycode, expected_kc);
        assert_eq!(state.key_grabs[0].modifiers, 0);
        assert!(state.button_grabs.is_empty());
    }

    /// `XIAllowEvents` with `mode=AsyncDevice(0)` releases the
    /// passive grab on the calling client's device, matching what
    /// mutter/cinnamon shell call after their click-to-focus button
    /// grab activates. Before this handler shipped, the call was a
    /// debug-logged stub so `state.pointer_grab` stayed pinned until
    /// the next ButtonRelease, leaking the grab across intermediate
    /// motion events.
    #[test]
    fn xi_allow_events_async_device_releases_passive_pointer_grab() {
        const CLIENT_ID: u32 = 1;
        const GRAB_WIN: u32 = 0x0010_0051;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        // Seed a passive grab that has activated (set by the
        // pointer-fanout Step 3 path when a click matched).
        state.pointer_grab = Some((ClientId(CLIENT_ID), ResourceId(GRAB_WIN)));
        state.pointer_grab_is_passive = true;

        // Body per `xXIAllowEventsReq`: time(4) + deviceid(2) +
        // mode(1) + pad(1). deviceid=2 (master pointer), mode=0
        // (AsyncDevice).
        let mut body = Vec::with_capacity(8);
        body.extend_from_slice(&0u32.to_le_bytes()); // time
        body.extend_from_slice(&2u16.to_le_bytes()); // deviceid
        body.push(0); // mode = AsyncDevice
        body.push(0); // pad

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 53,
            length_units: 3,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("allow events");

        assert!(
            state.pointer_grab.is_none(),
            "AsyncDevice releases the passive pointer grab"
        );
        assert!(!state.pointer_grab_is_passive);
    }

    #[test]
    fn xi_allow_events_replay_device_replays_frozen_button_press_to_target() {
        use crate::{
            backend::Backend,
            host_x11::{HostPointerEvent, PointerEventKind},
            resources::ROOT_VISUAL,
        };

        const GRAB_CLIENT_ID: u32 = 1;
        const TARGET_CLIENT_ID: u32 = 2;
        const GRAB_WIN: u32 = 0x0010_0051;
        const TARGET_WIN: u32 = 0x0020_0052;
        const HOST_XID: u32 = 0xCAFE_0001;

        let mut state = ServerState::new();
        let mut grab_peer = install_client(&mut state, GRAB_CLIENT_ID);
        let mut target_peer = install_client(&mut state, TARGET_CLIENT_ID);
        let mut backend = RecordingBackend::new();
        grab_peer
            .set_nonblocking(true)
            .expect("grab peer nonblocking");
        target_peer
            .set_nonblocking(true)
            .expect("target peer nonblocking");

        state.resources.create_window(
            ClientId(GRAB_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(GRAB_WIN),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 100,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        state.resources.create_window(
            ClientId(TARGET_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(TARGET_WIN),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 100,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        let _ = state.resources.map_window(ResourceId(GRAB_WIN));
        let _ = state.resources.map_window(ResourceId(TARGET_WIN));
        state
            .clients
            .get_mut(&TARGET_CLIENT_ID)
            .expect("target client")
            .event_masks
            .insert(ResourceId(TARGET_WIN), 0x0000_0004);

        state.pointer_grab = Some((ClientId(GRAB_CLIENT_ID), ResourceId(GRAB_WIN)));
        state.pointer_grab_is_passive = true;
        state.frozen_pointer_event = Some(HostPointerEvent {
            kind: PointerEventKind::ButtonPress,
            host_xid: HOST_XID,
            detail: 1,
            time: 0,
            root_x: 10,
            root_y: 10,
            event_x: 10,
            event_y: 10,
            state: 0,
            crossing_mode: 0,
            child: 0,
        });
        Backend::register_top_level(&mut backend, None, ResourceId(TARGET_WIN), HOST_XID)
            .expect("register host xid");

        let mut body = Vec::with_capacity(8);
        body.extend_from_slice(&0u32.to_le_bytes()); // time
        body.extend_from_slice(&2u16.to_le_bytes()); // deviceid
        body.push(2); // mode = ReplayDevice
        body.push(0); // pad

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 53,
            length_units: 3,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(GRAB_CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("allow events");

        assert!(state.pointer_grab.is_none());
        assert!(!state.pointer_grab_is_passive);
        assert!(state.frozen_pointer_event.is_none());

        let mut buf = [0u8; 32];
        let grab_read = grab_peer.read(&mut buf);
        assert!(
            matches!(grab_read, Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock),
            "grab owner must not receive replayed ButtonPress; got {grab_read:?}",
        );
        let target_read = target_peer.read(&mut buf);
        assert!(
            matches!(target_read, Ok(32)),
            "target window subscriber should receive replayed ButtonPress; got {target_read:?}",
        );
        assert_eq!(buf[0], 4, "event type should be ButtonPress");
        assert_eq!(&buf[12..16], &TARGET_WIN.to_le_bytes());
    }

    /// Regression for the MATE submenu-hover bug. mate-panel holds an
    /// active XI2 grab on its main panel window with `owner_events=true`;
    /// menu items it pops up are top-level override-redirect windows
    /// OWNED BY mate-panel (siblings of the grab window, not
    /// descendants). Pre-fix the active-grab-redirect check used pure
    /// topology (`target == grab_window || is_descendant_of`),
    /// which redirected motion on the menu items to the grab window
    /// with grab-relative coords — GTK couldn't track which menu item
    /// the cursor was over, hover-delay never fired the submenu.
    /// The fix adds an ownership-aware path: window owned by the grab
    /// client qualifies for natural delivery alongside descendants.
    /// Note: this is a heuristic — the fully spec-correct rule is "the
    /// event would normally be reported to the grab client" (a mask-
    /// subscription check). Ownership is a close proxy: clients almost
    /// always select events on windows they own.
    #[test]
    fn active_grab_owner_events_natural_delivery_to_sibling_window_owned_by_grab_client() {
        use crate::{
            backend::Backend,
            core_loop::pointer_fanout::pointer_event_fanout_to_state,
            host_x11::{HostPointerEvent, PointerEventKind},
            resources::ROOT_VISUAL,
            server::ActivePointerGrab,
        };

        const GRAB_CLIENT_ID: u32 = 1;
        const GRAB_WIN: u32 = 0x0010_0070;
        const SIBLING_WIN: u32 = 0x0010_0071; // top-level, owned by same client, not descendant of grab window
        const HOST_GRAB_XID: u32 = 0xCAFE_0070;
        const HOST_SIBLING_XID: u32 = 0xCAFE_0071;

        let mut state = ServerState::new();
        let mut peer = install_client(&mut state, GRAB_CLIENT_ID);
        let mut backend = RecordingBackend::new();
        peer.set_nonblocking(true).expect("nonblocking");

        // Create two top-level windows under root, both owned by the
        // grab client. They are siblings (both children of root), not
        // in an ancestor relationship — the exact topology for
        // mate-panel + popup-menu.
        for (xid, host_xid) in [(GRAB_WIN, HOST_GRAB_XID), (SIBLING_WIN, HOST_SIBLING_XID)] {
            state.resources.create_window(
                ClientId(GRAB_CLIENT_ID),
                yserver_protocol::x11::CreateWindowRequest {
                    depth: 24,
                    window: ResourceId(xid),
                    parent: ROOT_WINDOW,
                    x: 0,
                    y: 0,
                    width: 100,
                    height: 100,
                    border_width: 0,
                    class: 1,
                    visual: ROOT_VISUAL,
                    ..Default::default()
                },
            );
            let _ = state.resources.map_window(ResourceId(xid));
            Backend::register_top_level(&mut backend, None, ResourceId(xid), host_xid)
                .expect("register host xid");
        }
        // XI2 mask selecting motion on the sibling window (the menu
        // item the cursor will move over). XI_Motion evtype = 6 →
        // mask bit 1<<6 = 0x40.
        state
            .clients
            .get_mut(&GRAB_CLIENT_ID)
            .expect("client")
            .xi2_masks
            .insert((ResourceId(SIBLING_WIN), 2), 0x40);

        // Install active grab on GRAB_WIN with owner_events=true.
        state.pointer_grab = Some((ClientId(GRAB_CLIENT_ID), ResourceId(GRAB_WIN)));
        state.active_pointer_grab = Some(ActivePointerGrab {
            owner: ClientId(GRAB_CLIENT_ID),
            grab_window: ResourceId(GRAB_WIN),
            event_mask: 0,
            cursor: ResourceId(0),
            time: 0,
            owner_events: true,
        });
        // Sanity: sibling is NOT a descendant of grab window.
        assert!(
            !state
                .resources
                .is_descendant_of(ResourceId(SIBLING_WIN), ResourceId(GRAB_WIN))
        );
        // And IS owned by the grab client.
        assert_eq!(
            state.resources.window_owner(ResourceId(SIBLING_WIN)),
            Some(ClientId(GRAB_CLIENT_ID)),
        );

        // Cursor at root_x=50, root_y=50 — landing on SIBLING_WIN.
        // host_xid = SIBLING's host xid so the v2-style hit-test lands
        // on the sibling window naturally.
        let motion = HostPointerEvent {
            kind: PointerEventKind::MotionNotify,
            host_xid: HOST_SIBLING_XID,
            detail: 0,
            time: 0x1000,
            root_x: 50,
            root_y: 50,
            event_x: 50,
            event_y: 50,
            state: 0,
            crossing_mode: 0,
            child: 0,
        };
        let xid_map = backend.xid_map().clone();
        let _ =
            pointer_event_fanout_to_state(&mut state, &mut backend, &xid_map, motion, true, false);

        // Read whatever landed on the wire. With the ownership-aware
        // natural-delivery check, the XI2 motion must report against
        // the sibling window (event=SIBLING_WIN) with sensible coords
        // (event_x ≈ 50), NOT redirected to the grab window with
        // grab-relative coords. Pre-fix the event would be on
        // GRAB_WIN with grab-clamped coords — for this layout
        // (sibling at the same root origin) the difference might be
        // subtle in coords but the `event` window XID is the
        // smoking-gun: GRAB vs SIBLING.
        let mut buf = [0u8; 256];
        let n = peer.read(&mut buf).expect("client got at least one event");
        assert!(n >= 32, "expected at least one event, got {n} bytes");
        // Scan for a Generic XI2 event (type=35, second byte=major opcode of XInputExtension).
        // We just need to find the `event` window XID in the body.
        let mut found_sibling = false;
        let mut found_grab = false;
        let mut i = 0;
        while i + 32 <= n {
            // Generic event byte 0 is type. XI2 Motion event window
            // sits at a known offset; rather than parsing the full
            // event structure, scan for either window XID in the
            // first 64 bytes of the body. Cheap+robust.
            let slice = &buf[i..(i + 64).min(n)];
            if slice.windows(4).any(|w| w == SIBLING_WIN.to_le_bytes()) {
                found_sibling = true;
            }
            if slice.windows(4).any(|w| w == GRAB_WIN.to_le_bytes()) {
                found_grab = true;
            }
            i += 32;
        }
        assert!(
            found_sibling,
            "XI2 motion must address the sibling window (owner=grab client) under owner_events=true; got buf bytes {:?}",
            &buf[..n.min(64)],
        );
        // The grab window XID may also appear (e.g., in root/sourceid
        // fields by coincidence) so we don't assert !found_grab — the
        // load-bearing assertion is that the natural target window
        // shows up in the body.
        let _ = found_grab;
    }

    /// Regression for the MATE menu-click bug: when a release was
    /// queued during a sync passive grab freeze (because the WM hadn't
    /// yet called AllowEvents), the replay path MUST drain both the
    /// frozen press AND the queued release to the natural target — in
    /// that order. Pre-fix the release leaked through during freeze
    /// and the press was never replayed (frozen state cleared by the
    /// rogue release path), so the app saw release-then-nothing.
    #[test]
    fn xi_allow_events_replay_device_drains_queued_release_after_press() {
        use crate::{
            backend::Backend,
            host_x11::{HostPointerEvent, PointerEventKind},
            resources::ROOT_VISUAL,
        };

        const GRAB_CLIENT_ID: u32 = 1;
        const TARGET_CLIENT_ID: u32 = 2;
        const GRAB_WIN: u32 = 0x0010_0061;
        const TARGET_WIN: u32 = 0x0020_0062;
        const HOST_XID: u32 = 0xCAFE_0010;

        let mut state = ServerState::new();
        let mut grab_peer = install_client(&mut state, GRAB_CLIENT_ID);
        let mut target_peer = install_client(&mut state, TARGET_CLIENT_ID);
        let mut backend = RecordingBackend::new();
        grab_peer
            .set_nonblocking(true)
            .expect("grab peer nonblocking");
        target_peer
            .set_nonblocking(true)
            .expect("target peer nonblocking");

        state.resources.create_window(
            ClientId(GRAB_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(GRAB_WIN),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 100,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        state.resources.create_window(
            ClientId(TARGET_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(TARGET_WIN),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 100,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        let _ = state.resources.map_window(ResourceId(GRAB_WIN));
        let _ = state.resources.map_window(ResourceId(TARGET_WIN));
        // Target client selects ButtonPress | ButtonRelease.
        state
            .clients
            .get_mut(&TARGET_CLIENT_ID)
            .expect("target client")
            .event_masks
            .insert(ResourceId(TARGET_WIN), 0x0000_000c);

        state.pointer_grab = Some((ClientId(GRAB_CLIENT_ID), ResourceId(GRAB_WIN)));
        state.pointer_grab_is_passive = true;
        let press = HostPointerEvent {
            kind: PointerEventKind::ButtonPress,
            host_xid: HOST_XID,
            detail: 1,
            time: 0x1c33,
            root_x: 10,
            root_y: 10,
            event_x: 10,
            event_y: 10,
            state: 0,
            crossing_mode: 0,
            child: 0,
        };
        state.frozen_pointer_event = Some(press);
        // Queue a release that arrived while frozen.
        let release = HostPointerEvent {
            kind: PointerEventKind::ButtonRelease,
            time: 0x1c89,
            ..press
        };
        state.frozen_pointer_queue.push_back(release);
        Backend::register_top_level(&mut backend, None, ResourceId(TARGET_WIN), HOST_XID)
            .expect("register host xid");

        // XIAllowEvents ReplayDevice on master pointer (deviceid=2).
        let mut body = Vec::with_capacity(8);
        body.extend_from_slice(&0u32.to_le_bytes());
        body.extend_from_slice(&2u16.to_le_bytes());
        body.push(2); // mode = ReplayDevice
        body.push(0); // pad
        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 53,
            length_units: 3,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(GRAB_CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("allow events");

        // Both frozen slots cleared after drain.
        assert!(state.frozen_pointer_event.is_none());
        assert!(state.frozen_pointer_queue.is_empty());
        assert!(state.pointer_grab.is_none());

        // Grab owner must not receive the replayed events (they go to
        // the natural target).
        let mut buf = [0u8; 32];
        let grab_read = grab_peer.read(&mut buf);
        assert!(
            matches!(grab_read, Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock),
            "grab owner must not receive replay; got {grab_read:?}",
        );

        // Target must receive BOTH events in order. Read a sequence of
        // 32-byte core events, expecting Press(type=4) then
        // Release(type=5). The XI2 fanout would also fire (each event
        // shipping a GenericEvent), so we read until we've seen one
        // press and one release.
        let mut saw_press = false;
        let mut saw_release = false;
        let mut press_offset = usize::MAX;
        let mut release_offset = usize::MAX;
        let mut total_read = 0usize;
        // Slurp whatever the wire has — bound the read loop to avoid
        // hanging if something goes wrong.
        for iter in 0..8 {
            let mut chunk = [0u8; 256];
            match target_peer.read(&mut chunk) {
                Ok(0) => break,
                Ok(n) => {
                    // Scan 32-byte boundaries for core ButtonPress(4)
                    // / ButtonRelease(5). GenericEvents (XI2) are
                    // type=35 and longer; their first byte still
                    // shows up at a 32-byte offset.
                    let mut i = 0;
                    while i + 32 <= n {
                        let evt_type = chunk[i] & 0x7F;
                        if evt_type == 4 && !saw_press {
                            saw_press = true;
                            press_offset = total_read + i;
                        } else if evt_type == 5 && !saw_release {
                            saw_release = true;
                            release_offset = total_read + i;
                        }
                        // GenericEvent is variable-length; advance by 32 conservatively.
                        i += 32;
                    }
                    total_read += n;
                    if saw_press && saw_release {
                        break;
                    }
                }
                Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock => break,
                Err(e) => panic!("target read failed at iter {iter}: {e}"),
            }
        }
        assert!(saw_press, "target must receive replayed ButtonPress");
        assert!(saw_release, "target must receive queued ButtonRelease");
        assert!(
            press_offset < release_offset,
            "Press must arrive BEFORE Release at the target (got press@{press_offset}, release@{release_offset})",
        );
    }

    #[test]
    fn xi_allow_events_replay_device_releases_active_pointer_grab() {
        use crate::{backend::Backend, resources::ROOT_VISUAL, server::ActivePointerGrab};

        const GRAB_CLIENT_ID: u32 = 1;
        const TARGET_WIN: u32 = 0x0020_0052;
        const HOST_XID: u32 = 0xCAFE_0003;

        let mut state = ServerState::new();
        let _grab_peer = install_client(&mut state, GRAB_CLIENT_ID);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            ClientId(GRAB_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(TARGET_WIN),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 100,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        let _ = state.resources.map_window(ResourceId(TARGET_WIN));
        state.pointer_grab = Some((ClientId(GRAB_CLIENT_ID), ResourceId(TARGET_WIN)));
        state.pointer_grab_is_passive = false;
        state.active_pointer_grab = Some(ActivePointerGrab {
            owner: ClientId(GRAB_CLIENT_ID),
            grab_window: ResourceId(TARGET_WIN),
            event_mask: 0xFFFF,
            cursor: ResourceId(0),
            time: 0,
            owner_events: false,
        });
        Backend::register_top_level(&mut backend, None, ResourceId(TARGET_WIN), HOST_XID)
            .expect("register host xid");

        let mut body = Vec::with_capacity(8);
        body.extend_from_slice(&0u32.to_le_bytes()); // time
        body.extend_from_slice(&2u16.to_le_bytes()); // deviceid
        body.push(2); // mode = ReplayDevice
        body.push(0); // pad

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 53,
            length_units: 3,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(GRAB_CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("allow events replay pointer");

        assert!(state.pointer_grab.is_none());
        assert!(!state.pointer_grab_is_passive);
        assert!(state.active_pointer_grab.is_none());
    }

    #[test]
    fn xi_sync_passive_grab_replays_xi2_press_to_target_only_after_allow_events() {
        use crate::{
            backend::Backend,
            host_x11::{HostPointerEvent, PointerEventKind},
            resources::ROOT_VISUAL,
            server::PassiveButtonGrab,
        };

        const GRAB_CLIENT_ID: u32 = 1;
        const TARGET_CLIENT_ID: u32 = 2;
        const TARGET_WIN: u32 = 0x0020_0052;
        const HOST_XID: u32 = 0xCAFE_0002;
        const XI2_BUTTON_PRESS_BIT: u32 = 1 << 4;

        let mut state = ServerState::new();
        let mut grab_peer = install_client(&mut state, GRAB_CLIENT_ID);
        let mut target_peer = install_client(&mut state, TARGET_CLIENT_ID);
        let mut backend = RecordingBackend::new();
        grab_peer
            .set_nonblocking(true)
            .expect("grab peer nonblocking");
        target_peer
            .set_nonblocking(true)
            .expect("target peer nonblocking");

        state.resources.create_window(
            ClientId(TARGET_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(TARGET_WIN),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 100,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        let _ = state.resources.map_window(ResourceId(TARGET_WIN));
        state
            .clients
            .get_mut(&GRAB_CLIENT_ID)
            .expect("grab client")
            .xi2_masks
            .insert((ResourceId(TARGET_WIN), 1), XI2_BUTTON_PRESS_BIT);
        state
            .clients
            .get_mut(&TARGET_CLIENT_ID)
            .expect("target client")
            .xi2_masks
            .insert((ResourceId(TARGET_WIN), 1), XI2_BUTTON_PRESS_BIT);
        state.button_grabs.push(PassiveButtonGrab {
            owner: ClientId(GRAB_CLIENT_ID),
            grab_window: ResourceId(TARGET_WIN),
            button: 1,
            modifiers: 0,
            owner_events: false,
            event_mask: 0xFFFF_FFFF,
            pointer_mode: 0,
        });
        Backend::register_top_level(&mut backend, None, ResourceId(TARGET_WIN), HOST_XID)
            .expect("register host xid");

        let event = HostPointerEvent {
            kind: PointerEventKind::ButtonPress,
            host_xid: HOST_XID,
            detail: 1,
            time: 0x1234,
            root_x: 10,
            root_y: 10,
            event_x: 10,
            event_y: 10,
            state: 0,
            crossing_mode: 0,
            child: 0,
        };
        let xid_map = backend.xid_map().clone();
        let _dropped =
            pointer_event_fanout_to_state(&mut state, &mut backend, &xid_map, event, true, false);

        assert!(state.pointer_grab_is_passive);
        assert!(state.frozen_pointer_event.is_some());

        let mut buf = [0u8; 128];
        let target_read = target_peer.read(&mut buf);
        assert!(
            matches!(target_read, Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock),
            "sync passive XI2 grab must withhold the initial XI2 press from the target; got {target_read:?}",
        );
        let grab_read = grab_peer.read(&mut buf);
        assert!(
            matches!(grab_read, Ok(n) if n > 0),
            "grab owner should receive the grabbed press stream; got {grab_read:?}",
        );

        let mut body = Vec::with_capacity(8);
        body.extend_from_slice(&0x1234u32.to_le_bytes()); // time
        body.extend_from_slice(&2u16.to_le_bytes()); // deviceid
        body.push(2); // mode = ReplayDevice
        body.push(0); // pad

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 53,
            length_units: 3,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(GRAB_CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("allow events");

        let target_read = target_peer.read(&mut buf);
        assert!(
            matches!(target_read, Ok(n) if n >= 32 && buf[0] == 35),
            "ReplayDevice must redeliver the XI2 press to the natural target; got {target_read:?}",
        );
    }

    #[test]
    fn xi_sync_passive_grab_release_during_freeze_queues_for_replay() {
        // Regression: in a sync passive grab, a ButtonRelease arriving
        // BEFORE the grab owner sends AllowEvents must NOT clear the
        // grab nor leak to the natural target — it must queue alongside
        // the activating press for replay. Pre-fix, the release cleared
        // `frozen_pointer_event` + `pointer_grab_is_passive`, so when
        // AllowEvents(ReplayPointer/ReplayDevice) finally arrived there
        // was nothing to replay. Visible symptom on MATE: marco's slow
        // ~10 round-trip grab handler vs a fast click → app never sees
        // the press → menu/titlebar clicks dead.
        use crate::{
            backend::Backend,
            host_x11::{HostPointerEvent, PointerEventKind},
            resources::ROOT_VISUAL,
            server::PassiveButtonGrab,
        };

        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0020_0053;
        const HOST_XID: u32 = 0xCAFE_0004;

        let mut state = ServerState::new();
        let _peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();

        state.resources.create_window(
            ClientId(CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(WINDOW_XID),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 100,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        let _ = state.resources.map_window(ResourceId(WINDOW_XID));
        state.button_grabs.push(PassiveButtonGrab {
            owner: ClientId(CLIENT_ID),
            grab_window: ResourceId(WINDOW_XID),
            button: 1,
            modifiers: 0,
            owner_events: true,
            event_mask: 0xFFFF_FFFF,
            pointer_mode: 0, // Synchronous → triggers freeze
        });
        Backend::register_top_level(&mut backend, None, ResourceId(WINDOW_XID), HOST_XID)
            .expect("register host xid");

        let press = HostPointerEvent {
            kind: PointerEventKind::ButtonPress,
            host_xid: HOST_XID,
            detail: 1,
            time: 0x1234,
            root_x: 10,
            root_y: 10,
            event_x: 10,
            event_y: 10,
            state: 0,
            crossing_mode: 0,
            child: 0,
        };
        let xid_map = backend.xid_map().clone();
        let _dropped =
            pointer_event_fanout_to_state(&mut state, &mut backend, &xid_map, press, true, false);
        assert!(state.pointer_grab_is_passive);
        assert!(state.frozen_pointer_event.is_some());
        assert!(state.frozen_pointer_queue.is_empty());

        // Release arrives BEFORE AllowEvents (the load-bearing case).
        let release = HostPointerEvent {
            kind: PointerEventKind::ButtonRelease,
            time: 0x1280,
            ..press
        };
        let xid_map = backend.xid_map().clone();
        let _dropped =
            pointer_event_fanout_to_state(&mut state, &mut backend, &xid_map, release, true, false);

        // Grab MUST still be active (waiting for AllowEvents). Press
        // is still frozen. Release is in the queue.
        assert!(
            state.pointer_grab.is_some(),
            "grab must remain active while frozen — release waits for AllowEvents",
        );
        assert!(state.pointer_grab_is_passive);
        assert!(state.frozen_pointer_event.is_some());
        assert_eq!(
            state.frozen_pointer_queue.len(),
            1,
            "release must be queued for replay, not delivered to natural target",
        );
        assert_eq!(
            state
                .frozen_pointer_queue
                .front()
                .map(|e| e.kind)
                .expect("queued event present"),
            PointerEventKind::ButtonRelease,
        );
    }

    #[test]
    fn xi_passive_grab_owner_events_delivers_descendant_window_regardless_of_owner() {
        use crate::{
            backend::Backend,
            host_x11::{HostPointerEvent, PointerEventKind},
            resources::ROOT_VISUAL,
            server::PassiveButtonGrab,
        };

        const GRAB_CLIENT_ID: u32 = 1;
        const CHILD_CLIENT_ID: u32 = 2;
        const GRAB_WIN: u32 = 0x0020_0062;
        const CHILD_WIN: u32 = 0x0020_0063;
        const HOST_XID: u32 = 0xCAFE_0005;

        let mut state = ServerState::new();
        let mut grab_peer = install_client(&mut state, GRAB_CLIENT_ID);
        let mut child_peer = install_client(&mut state, CHILD_CLIENT_ID);
        let mut backend = RecordingBackend::new();
        grab_peer
            .set_nonblocking(true)
            .expect("grab peer nonblocking");
        child_peer
            .set_nonblocking(true)
            .expect("child peer nonblocking");

        state.resources.create_window(
            ClientId(GRAB_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(GRAB_WIN),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 100,
                height: 100,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        state.resources.create_window(
            ClientId(CHILD_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(CHILD_WIN),
                parent: ResourceId(GRAB_WIN),
                x: 10,
                y: 10,
                width: 40,
                height: 40,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        let _ = state.resources.map_window(ResourceId(GRAB_WIN));
        let _ = state.resources.map_window(ResourceId(CHILD_WIN));
        state
            .clients
            .get_mut(&CHILD_CLIENT_ID)
            .expect("child client")
            .event_masks
            .insert(ResourceId(CHILD_WIN), 0x0000_0004);
        state.button_grabs.push(PassiveButtonGrab {
            owner: ClientId(GRAB_CLIENT_ID),
            grab_window: ResourceId(GRAB_WIN),
            button: 1,
            modifiers: 0,
            owner_events: true,
            event_mask: 0xFFFF_FFFF,
            pointer_mode: 0,
        });
        Backend::register_top_level(&mut backend, None, ResourceId(GRAB_WIN), HOST_XID)
            .expect("register host xid");

        let press = HostPointerEvent {
            kind: PointerEventKind::ButtonPress,
            host_xid: HOST_XID,
            detail: 1,
            time: 0x1234,
            root_x: 20,
            root_y: 20,
            event_x: 20,
            event_y: 20,
            state: 0,
            crossing_mode: 0,
            child: 0,
        };
        let xid_map = backend.xid_map().clone();
        let _dropped =
            pointer_event_fanout_to_state(&mut state, &mut backend, &xid_map, press, true, false);

        let mut buf = [0u8; 128];
        let child_read = child_peer.read(&mut buf);
        assert!(
            matches!(child_read, Ok(n) if n >= 32),
            "owner_events=true passive grab must deliver descendant clicks to the descendant window even when a different client owns it; got {child_read:?}",
        );
        let grab_read = grab_peer.read(&mut buf);
        assert!(
            matches!(grab_read, Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock),
            "owner_events=true passive grab must not redirect descendant clicks to the grab owner; got {grab_read:?}",
        );
    }

    /// During a window move, muffin holds an *active* `XIGrabDevice` on
    /// the master pointer. Every master-pointer XI2 event — including the
    /// final `XI_ButtonRelease` — must be funnelled to the grab owner,
    /// even after the drag has pulled the pointer over another client's
    /// window. Regression: the XI2 fanout routed purely by window
    /// mask-selection and ignored the active grab, so the release was
    /// delivered to the window under the cursor (nemo-desktop) instead of
    /// the grab owner (muffin) — leaving muffin stuck in its move loop
    /// with the button apparently still held.
    #[test]
    fn xi_active_device_grab_funnels_button_release_to_grab_owner_not_window_under_cursor() {
        use crate::{
            backend::Backend,
            host_x11::{HostPointerEvent, PointerEventKind},
            resources::ROOT_VISUAL,
            server::ActivePointerGrab,
        };

        const GRAB_CLIENT_ID: u32 = 1; // muffin
        const OTHER_CLIENT_ID: u32 = 2; // nemo-desktop
        const GRAB_WIN: u32 = 0x0010_0011; // muffin's grab window
        const OTHER_WIN: u32 = 0x0025_0003; // nemo-desktop fullscreen window
        const OTHER_HOST_XID: u32 = 0xCAFE_0006;
        const XI2_BUTTON_RELEASE_BIT: u32 = 1 << 5;

        let mut state = ServerState::new();
        let mut grab_peer = install_client(&mut state, GRAB_CLIENT_ID);
        let mut other_peer = install_client(&mut state, OTHER_CLIENT_ID);
        let mut backend = RecordingBackend::new();
        grab_peer.set_nonblocking(true).unwrap();
        other_peer.set_nonblocking(true).unwrap();

        // muffin's grab window — small, off in the corner. The drag pulls
        // the pointer away from it onto the desktop.
        state.resources.create_window(
            ClientId(GRAB_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(GRAB_WIN),
                parent: ROOT_WINDOW,
                x: 0,
                y: 0,
                width: 50,
                height: 50,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        // nemo-desktop's window — covers where the pointer ends up.
        state.resources.create_window(
            ClientId(OTHER_CLIENT_ID),
            yserver_protocol::x11::CreateWindowRequest {
                depth: 24,
                window: ResourceId(OTHER_WIN),
                parent: ROOT_WINDOW,
                x: 200,
                y: 200,
                width: 400,
                height: 400,
                border_width: 0,
                class: 1,
                visual: ROOT_VISUAL,
                ..Default::default()
            },
        );
        let _ = state.resources.map_window(ResourceId(GRAB_WIN));
        let _ = state.resources.map_window(ResourceId(OTHER_WIN));

        // nemo selects XI2 ButtonRelease on its own window (XIAllDevices=1).
        state
            .clients
            .get_mut(&OTHER_CLIENT_ID)
            .expect("other client")
            .xi2_masks
            .insert((ResourceId(OTHER_WIN), 1), XI2_BUTTON_RELEASE_BIT);

        // muffin holds an active master-pointer grab (XIGrabDevice).
        // owner_events=false → every event funnels to the grab owner.
        state.pointer_grab = Some((ClientId(GRAB_CLIENT_ID), ResourceId(GRAB_WIN)));
        state.pointer_grab_is_passive = false;
        state.active_pointer_grab = Some(ActivePointerGrab {
            owner: ClientId(GRAB_CLIENT_ID),
            grab_window: ResourceId(GRAB_WIN),
            event_mask: 0xFFFF,
            cursor: ResourceId(0),
            time: 0,
            owner_events: false,
        });

        Backend::register_top_level(&mut backend, None, ResourceId(OTHER_WIN), OTHER_HOST_XID)
            .expect("register host xid");

        // Pointer has dragged onto nemo-desktop (200,200..600,600); button 1
        // still held. event_x/y are relative to OTHER_WIN's origin.
        let release = HostPointerEvent {
            kind: PointerEventKind::ButtonRelease,
            host_xid: OTHER_HOST_XID,
            detail: 1,
            time: 0x2000,
            root_x: 300,
            root_y: 300,
            event_x: 100,
            event_y: 100,
            state: 0x100, // button 1 down
            crossing_mode: 0,
            child: 0,
        };
        let xid_map = backend.xid_map().clone();
        let _dropped =
            pointer_event_fanout_to_state(&mut state, &mut backend, &xid_map, release, true, false);

        let mut buf = [0u8; 256];

        // The window under the cursor must NOT get the XI2 release — the
        // active grab owns the device.
        let other_read = other_peer.read(&mut buf);
        assert!(
            matches!(other_read, Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock),
            "active device grab must withhold the XI2 ButtonRelease from the window under the cursor; got {other_read:?}",
        );

        // The grab owner must receive the XI2 ButtonRelease. The grab owner
        // also gets the parallel core ButtonRelease (32 bytes) from the
        // core redirect, so scan event boundaries for the XI2 GenericEvent.
        let n = match grab_peer.read(&mut buf) {
            Ok(n) => n,
            Err(e) => panic!("grab owner must receive the grabbed XI2 release; got {e:?}"),
        };
        let off = (0..n)
            .step_by(32)
            .find(|&off| off + 10 <= n && buf[off] == 35)
            .expect("grab owner must receive an XI2 GenericEvent (got core-only stream)");
        assert_eq!(
            u16::from_le_bytes([buf[off + 8], buf[off + 9]]),
            5,
            "the grabbed XI2 event must be a ButtonRelease (evtype 5)",
        );
    }

    /// `XIQueryPointer` must report currently-held pointer buttons in
    /// the XI2 `buttons` bitmask, not only in the legacy KeyButMask
    /// `effective_mods`. A GTK4 CSD window move goes through
    /// `_NET_WM_MOVERESIZE`: the app sends the request and muffin — which
    /// never saw the ButtonPress — queries the pointer to learn whether
    /// the initiating button is still held. With an empty `buttons` mask
    /// muffin concluded the button was released and aborted the move
    /// grab immediately (the window "didn't budge"). Button N maps to
    /// bit N (button 1 -> bit 1).
    #[test]
    fn xi_query_pointer_reports_held_button_in_xi2_button_mask() {
        use crate::{backend::Backend, resources::ROOT_VISUAL};
        use yserver_protocol::x11::ClientByteOrder;

        const CLIENT_ID: u32 = 1;
        const WINDOW_XID: u32 = 0x0020_0070;
        const HOST_XID: u32 = 0xCAFE_0007;

        // Run for both client byte orders. The XI2 button mask is a raw
        // byte array indexed by `XIMaskIsSet` (X11/extensions/XI2.h), so it
        // must NOT be byte-swapped per client order — a big-endian client
        // must still read button 1 in mask byte 0.
        for order in [ClientByteOrder::LittleEndian, ClientByteOrder::BigEndian] {
            let mut state = ServerState::new();
            let mut peer = install_client(&mut state, CLIENT_ID);
            peer.set_nonblocking(true).unwrap();
            state.clients.get_mut(&CLIENT_ID).unwrap().byte_order = order;
            let mut backend = RecordingBackend::new();
            // Model button 1 held (KeyButMask Button1Mask = 0x0100).
            backend.query_pointer_mask = 0x0100;

            state.resources.create_window(
                yserver_protocol::x11::ClientId(CLIENT_ID),
                yserver_protocol::x11::CreateWindowRequest {
                    depth: 24,
                    window: ResourceId(WINDOW_XID),
                    parent: ROOT_WINDOW,
                    x: 0,
                    y: 0,
                    width: 100,
                    height: 100,
                    border_width: 0,
                    class: 1,
                    visual: ROOT_VISUAL,
                    ..Default::default()
                },
            );
            let _ = state.resources.map_window(ResourceId(WINDOW_XID));
            Backend::register_top_level(&mut backend, None, ResourceId(WINDOW_XID), HOST_XID)
                .expect("register host xid");

            // XIQueryPointer body: window(4) + deviceid(2) + pad(2).
            let mut body = Vec::with_capacity(8);
            body.extend_from_slice(&WINDOW_XID.to_le_bytes());
            body.extend_from_slice(&2u16.to_le_bytes()); // master pointer
            body.extend_from_slice(&0u16.to_le_bytes()); // pad

            let header = yserver_protocol::x11::RequestHeader {
                opcode: 131,
                data: 40, // XIQueryPointer
                length_units: 3,
            };
            handle_xi2_request(
                &mut state,
                &mut backend,
                None,
                ClientId(CLIENT_ID),
                SequenceNumber(1),
                header,
                &body,
            )
            .expect("xi query pointer");

            let mut buf = [0u8; 128];
            let n = peer.read(&mut buf).expect("reply");
            // Reply: 8-byte header + 24 coord bytes; same_screen@32, pad@33,
            // buttons_len@34-35, mods@36-51, group@52-55, button mask@56+.
            assert!(
                n >= 60,
                "{order:?}: XIQueryPointer reply must carry a 1-unit button bitmask (got {n})",
            );
            let buttons_len = match order {
                ClientByteOrder::LittleEndian => u16::from_le_bytes([buf[34], buf[35]]),
                ClientByteOrder::BigEndian => u16::from_be_bytes([buf[34], buf[35]]),
            };
            assert_eq!(
                buttons_len, 1,
                "{order:?}: buttons_len must be 1 so clients can read button state",
            );
            // Byte-indexed exactly as `XIMaskIsSet(mask, 1) = mask[1>>3] &
            // (1 << (1 & 7)) = mask[0] & 0x02` (the way muffin reads it),
            // which is byte-order independent.
            assert_ne!(
                buf[56] & (1 << 1),
                0,
                "{order:?}: button 1 must be held in XI2 button mask byte 0 \
                 (raw byte array, not byte-swapped); muffin's \
                 _NET_WM_MOVERESIZE move aborts on an empty mask",
            );
        }
    }

    /// `XIGetClientPointer` reply must place `deviceid` at bytes 10-11.
    /// Per `xXIGetClientPointerReply` (X11/extensions/XI2proto.h):
    /// `set` at byte 8, `pad0` at byte 9, `deviceid` (u16) at bytes
    /// 10-11. Regression: the encoder wrote 3 pad bytes after `set`,
    /// pushing deviceid to bytes 12-13, so clients read deviceid=0.
    /// nemo's desktop rubber-band asks `XIGetClientPointer` for its
    /// pointer device, got 0, and queried that for the band anchor —
    /// anchoring it at (0,0). caja never calls it, so it was immune.
    #[test]
    fn xi_get_client_pointer_reply_deviceid_offset() {
        const CLIENT_ID: u32 = 1;

        let mut state = ServerState::new();
        let mut peer = install_client(&mut state, CLIENT_ID);
        peer.set_nonblocking(true).unwrap();
        let mut backend = RecordingBackend::new();

        // XIGetClientPointer body: window(4).
        let body = 0u32.to_le_bytes().to_vec();
        let header = yserver_protocol::x11::RequestHeader {
            opcode: 131,
            data: 45, // XIGetClientPointer
            length_units: 2,
        };
        handle_xi2_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &body,
        )
        .expect("xi get client pointer");

        let mut buf = [0u8; 64];
        let n = peer.read(&mut buf).expect("reply");
        assert_eq!(n, 32, "reply must be 32 bytes");
        assert_eq!(buf[8], 1, "byte 8: set = True");
        assert_eq!(
            u16::from_le_bytes([buf[10], buf[11]]),
            2,
            "deviceid (bytes 10-11 per xXIGetClientPointerReply) must be the \
             master pointer (2); a wrong offset reads as 0 and breaks nemo's \
             pointer-device lookup for the rubber-band anchor",
        );
    }

    /// XI2 `FocusIn`/`FocusOut` events share the `xXIEnterEvent` layout
    /// and must carry the current pointer position (Xorg populates
    /// root_x/root_y/event_x/event_y from it). yserver emits focus events
    /// from request handlers that have no backend handle, so it reads the
    /// cached `state.pointer_root`. Regression target: focus events
    /// shipped at (0,0).
    #[test]
    fn xi_focus_in_carries_cached_pointer_position() {
        use crate::resources::ROOT_VISUAL;

        const CLIENT_ID: u32 = 1;
        const FOCUS_WIN: u32 = 0x0010_0007;
        const PREV_WIN: u32 = 0x0010_0008;
        const XI_FOCUS_IN: u16 = 9;

        let mut state = ServerState::new();
        let mut peer = install_client(&mut state, CLIENT_ID);
        peer.set_nonblocking(true).unwrap();

        for xid in [FOCUS_WIN, PREV_WIN] {
            state.resources.create_window(
                yserver_protocol::x11::ClientId(CLIENT_ID),
                yserver_protocol::x11::CreateWindowRequest {
                    depth: 24,
                    window: ResourceId(xid),
                    parent: ROOT_WINDOW,
                    x: 0,
                    y: 0,
                    width: 100,
                    height: 100,
                    border_width: 0,
                    class: 1,
                    visual: ROOT_VISUAL,
                    ..Default::default()
                },
            );
            let _ = state.resources.map_window(ResourceId(xid));
        }
        // Client selects XI_FocusIn on FOCUS_WIN (keyboard device 3).
        state
            .clients
            .get_mut(&CLIENT_ID)
            .unwrap()
            .xi2_masks
            .insert((ResourceId(FOCUS_WIN), 3), 1 << XI_FOCUS_IN);

        // Cache the pointer position; prior focus is on an unrelated window
        // so a Focus crossing actually fires onto FOCUS_WIN.
        state.pointer_root = (631, 641);
        state.clients.get_mut(&CLIENT_ID).unwrap().focused_window = ResourceId(PREV_WIN);

        set_focused_window_to_state(&mut state, ClientId(CLIENT_ID), ResourceId(FOCUS_WIN));

        let mut buf = [0u8; 128];
        let n = peer.read(&mut buf).expect("focus event");
        assert!(n >= 36, "expected an XI2 focus event (got {n} bytes)");
        assert_eq!(buf[0], 35, "must be an XI2 GenericEvent");
        assert_eq!(
            u16::from_le_bytes([buf[8], buf[9]]),
            XI_FOCUS_IN,
            "evtype must be FocusIn",
        );
        // root_x is FP1616 at bytes 32-35 (after the 32-byte boundary).
        let root_x_fp = u32::from_le_bytes([buf[32], buf[33], buf[34], buf[35]]);
        assert_eq!(
            root_x_fp,
            (631i32 << 16) as u32,
            "FocusIn must carry the current pointer X (631), not 0; Xorg \
             populates focus-event coords from the pointer position",
        );
    }

    /// Core `AllowEvents(ReplayKeyboard)` (mode 5 — what muffin/mutter
    /// calls for a declined key) releases the passive keyboard grab and
    /// replays the frozen key to the focused window. This is the
    /// dead-`p`-in-wezterm fix end-to-end: a sync passive key grab held
    /// `p`, the WM declined it, and ReplayKeyboard hands it to the
    /// focused client.
    #[test]
    fn core_replay_keyboard_releases_grab_and_replays_to_focus() {
        use crate::{
            host_x11::HostKeyEvent,
            server::{ActiveKeyboardGrab, ActiveKeyboardGrabSource},
        };

        const GRAB_CLIENT_ID: u32 = 1;
        const FOCUS_CLIENT_ID: u32 = 2;
        const FOCUS_WIN: u32 = 0x0020_0061;
        const KEY_PRESS_MASK: u32 = 0x0000_0001;

        let mut state = ServerState::new();
        let mut backend = RecordingBackend::new();
        let _grab_peer = install_client(&mut state, GRAB_CLIENT_ID);
        let mut focus_peer = install_client(&mut state, FOCUS_CLIENT_ID);
        focus_peer.set_nonblocking(true).unwrap();

        // Focused client selects core KeyPress on its window.
        {
            let c = state.clients.get_mut(&FOCUS_CLIENT_ID).unwrap();
            c.focused_window = ResourceId(FOCUS_WIN);
            c.event_masks.insert(ResourceId(FOCUS_WIN), KEY_PRESS_MASK);
        }

        // A sync passive key grab held by the WM is active, with a
        // frozen press waiting.
        state.active_keyboard_grab = Some(ActiveKeyboardGrab {
            owner: ClientId(GRAB_CLIENT_ID),
            grab_window: ROOT_WINDOW,
            source: ActiveKeyboardGrabSource::PassiveKey { keycode: 33 },
        });
        state.frozen_keyboard_event = Some(HostKeyEvent {
            pressed: true,
            keycode: 33,
            time: 0x1234,
            root_x: 10,
            root_y: 20,
            event_x: 10,
            event_y: 20,
            state: 0,
        });

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 35,
            data: 5, // ReplayKeyboard
            length_units: 2,
        };
        handle_allow_events(
            &mut state,
            &mut backend,
            ClientId(GRAB_CLIENT_ID),
            SequenceNumber(1),
            header,
        )
        .expect("allow events replay keyboard");

        assert!(
            state.active_keyboard_grab.is_none(),
            "ReplayKeyboard must release the passive keyboard grab"
        );
        assert!(
            state.frozen_keyboard_event.is_none(),
            "the frozen key must be consumed by the replay"
        );
        let mut buf = [0u8; 64];
        let n = focus_peer.read(&mut buf).unwrap_or(0);
        assert!(
            n >= 32 && buf[0] == 2,
            "replayed KeyPress (event type 2) must reach the focused client; got n={n} type={}",
            buf[0]
        );
    }

    /// XFixes `SetCursorName(cursor, "name")` interns the name as an
    /// atom and stores it on the cursor; the subsequent
    /// `GetCursorName(cursor)` returns the same atom + name bytes.
    /// A cursor that was never named reports atom=0 (None) + empty
    /// name, matching Xorg `xfixes/cursor.c:ProcXFixesGetCursorName`'s
    /// `pCursor->name == 0` branch.
    #[test]
    fn xfixes_cursor_name_round_trip() {
        use std::io::Read;

        const CLIENT_ID: u32 = 1;
        const CURSOR_XID: u32 = 0x0090_0042;

        let mut state = ServerState::new();
        let mut peer = install_client(&mut state, CLIENT_ID);
        let mut backend = RecordingBackend::new();
        state
            .resources
            .create_cursor(ClientId(CLIENT_ID), ResourceId(CURSOR_XID));

        let name = b"xterm";
        // SetCursorName body: cursor(4) + nbytes(2) + pad(2) + name + pad.
        let mut set_body = Vec::with_capacity(16);
        set_body.extend_from_slice(&CURSOR_XID.to_le_bytes());
        #[allow(clippy::cast_possible_truncation)]
        set_body.extend_from_slice(&(name.len() as u16).to_le_bytes());
        set_body.extend_from_slice(&[0u8; 2]);
        set_body.extend_from_slice(name);
        while !set_body.len().is_multiple_of(4) {
            set_body.push(0);
        }

        let header = yserver_protocol::x11::RequestHeader {
            opcode: 140, // XFIXES major (dispatcher reads minor from header.data)
            data: 23,    // SET_CURSOR_NAME
            length_units: 3,
        };
        handle_xfixes_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &set_body,
        )
        .expect("SetCursorName");

        // The atom must be stored on the cursor and resolve back to
        // the original name.
        let stored = state
            .resources
            .cursor_name_atom(ResourceId(CURSOR_XID))
            .expect("name atom present after SetCursorName");
        assert!(stored.0 != 0, "non-None atom expected for non-empty name");
        assert_eq!(
            state.atoms.name(stored).map(str::as_bytes),
            Some(name.as_ref()),
            "interned atom must reverse-resolve to the original name",
        );

        // GetCursorName body: cursor(4).
        let get_body = CURSOR_XID.to_le_bytes().to_vec();
        let get_header = yserver_protocol::x11::RequestHeader {
            opcode: 140,
            data: 24, // GET_CURSOR_NAME
            length_units: 2,
        };
        handle_xfixes_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(2),
            get_header,
            &get_body,
        )
        .expect("GetCursorName");

        peer.set_nonblocking(true).unwrap();
        let mut wire = Vec::new();
        let mut tmp = [0u8; 1024];
        loop {
            match peer.read(&mut tmp) {
                Ok(0) => break,
                Ok(n) => wire.extend_from_slice(&tmp[..n]),
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => break,
                Err(_) => break,
            }
        }
        // Reply layout: type(1) + pad(1) + sequence(2) + length(4) +
        // atom(4) + nbytes(2) + pad(18) + name(n) + pad-to-4.
        assert_eq!(wire[0], 1, "X_Reply type byte");
        let reply_atom = u32::from_le_bytes(wire[8..12].try_into().unwrap());
        let reply_nbytes = u16::from_le_bytes(wire[12..14].try_into().unwrap()) as usize;
        assert_eq!(reply_atom, stored.0, "reply atom matches stored atom");
        assert_eq!(reply_nbytes, name.len());
        assert_eq!(
            &wire[32..32 + name.len()],
            name,
            "reply name bytes match the original",
        );

        // GetCursorName on an unnamed cursor → atom=0, nbytes=0.
        const UNNAMED_XID: u32 = 0x0090_0099;
        state
            .resources
            .create_cursor(ClientId(CLIENT_ID), ResourceId(UNNAMED_XID));
        let get_body = UNNAMED_XID.to_le_bytes().to_vec();
        handle_xfixes_request(
            &mut state,
            &mut backend,
            None,
            ClientId(CLIENT_ID),
            SequenceNumber(3),
            get_header,
            &get_body,
        )
        .expect("GetCursorName unnamed");
        let mut wire2 = Vec::new();
        loop {
            match peer.read(&mut tmp) {
                Ok(0) => break,
                Ok(n) => wire2.extend_from_slice(&tmp[..n]),
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => break,
                Err(_) => break,
            }
        }
        let reply_atom = u32::from_le_bytes(wire2[8..12].try_into().unwrap());
        let reply_nbytes = u16::from_le_bytes(wire2[12..14].try_into().unwrap()) as usize;
        assert_eq!(reply_atom, 0, "unnamed cursor reports atom=0 (None)");
        assert_eq!(reply_nbytes, 0, "unnamed cursor reports empty name");
    }

    /// RANDR `SetCrtcConfig` with a mode that yserver advertises
    /// (the KMS-set one) replies status=0 (Success); with a mode
    /// not in `state.randr.modes`, replies status=3 (Failed). The
    /// "disable CRTC" form (mode=0) is always accepted. yserver
    /// itself does not reconfigure outputs — this is just the
    /// protocol-side answer.
    #[test]
    fn randr_set_crtc_config_validates_mode_id() {
        use crate::randr::{RandrOutput, RandrState};

        const CLIENT_ID: u32 = 1;
        let outputs = vec![RandrOutput {
            name: "test-0".to_string(),
            output_id: 1,
            crtc_id: 2,
            mode_id: 3,
            x: 0,
            y: 0,
            width: 1920,
            height: 1080,
            vrefresh: 60,
            mm_width: 0,
            mm_height: 0,
        }];
        let mut state = ServerState::new();
        state.randr = RandrState::from_outputs(0, outputs);
        let mut peer = install_client(&mut state, CLIENT_ID);

        // Build a SetCrtcConfig body: crtc(4) ts(4) cts(4) x(2) y(2)
        // mode(4) rotation(2) pad(2) outputs(4*N).
        fn build_body(mode: u32) -> Vec<u8> {
            let mut b = Vec::with_capacity(28);
            b.extend_from_slice(&2u32.to_le_bytes()); // crtc
            b.extend_from_slice(&0u32.to_le_bytes()); // timestamp
            b.extend_from_slice(&0u32.to_le_bytes()); // config_timestamp
            b.extend_from_slice(&0i16.to_le_bytes()); // x
            b.extend_from_slice(&0i16.to_le_bytes()); // y
            b.extend_from_slice(&mode.to_le_bytes()); // mode
            b.extend_from_slice(&1u16.to_le_bytes()); // rotation
            b.extend_from_slice(&[0u8; 2]); // pad
            b
        }
        let header = yserver_protocol::x11::RequestHeader {
            opcode: 140, // RANDR major (placeholder; dispatcher reads minor from header.data)
            data: 21,    // RR_SET_CRTC_CONFIG
            length_units: 7,
        };

        // Known mode → status=0 (Success).
        handle_randr_request(
            &mut state,
            ClientId(CLIENT_ID),
            SequenceNumber(1),
            header,
            &build_body(3),
        )
        .expect("known mode");
        // mode=0 (disable) → status=0.
        handle_randr_request(
            &mut state,
            ClientId(CLIENT_ID),
            SequenceNumber(2),
            header,
            &build_body(0),
        )
        .expect("disable");
        // Unknown mode → status=3 (Failed).
        handle_randr_request(
            &mut state,
            ClientId(CLIENT_ID),
            SequenceNumber(3),
            header,
            &build_body(0xdead_beef),
        )
        .expect("unknown mode");

        use std::io::Read;
        peer.set_nonblocking(true).unwrap();
        let mut wire = Vec::new();
        let mut tmp = [0u8; 1024];
        loop {
            match peer.read(&mut tmp) {
                Ok(0) => break,
                Ok(n) => wire.extend_from_slice(&tmp[..n]),
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => break,
                Err(_) => break,
            }
        }
        // Each reply is 32 bytes. status byte is at offset 1.
        let statuses: Vec<u8> = wire.chunks_exact(32).map(|c| c[1]).collect();
        assert_eq!(
            statuses,
            vec![0, 0, 3],
            "SetCrtcConfig must return Success(0) for advertised modes \
             and mode=0 (disable), Failed(3) for modes yserver does not \
             know about. Pre-fix every call returned 0 unconditionally, \
             so a client could `Success`-fully request a mode that was \
             never honoured.",
        );
    }

